/// BTInputDate — tap-to-open date / date-range input field.
///
/// Opens [BTCalendar] as a centered dialog or a bottom-sheet drawer depending
/// on [showType]. Use the named constructors to pick the mode:
/// - [BTInputDate.single] — picks a single [DateTime]
/// - [BTInputDate.range]  — picks a [DateTimeRange]
///
/// ## Usage
/// ```dart
/// // Single — controlled
/// BTInputDate.single(
///   label: 'Tanggal Lahir',
///   required: true,
///   value: _date,
///   locale: 'id',
///   showType: BTCalendarShowType.drawer,
///   onChanged: (d) => setState(() => _date = d),
///   onClear: () => setState(() => _date = null),
/// )
///
/// // Range — in a Form
/// BTInputDate.range(
///   label: 'Periode',
///   required: true,
///   rangeValue: _range,
///   onRangeChanged: (r) => setState(() => _range = r),
///   rangeValidator: (r) => r == null ? 'Pilih tanggal' : null,
/// )
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/molecules/input/input.types.dart';
import '../../calendar/calendar.types.dart';
import '../../calendar/calendar.widget.dart';
import '../../calendar/internal/calendar.utils.dart';
import 'package:flutter/material.dart';

class BTInputDate extends StatefulWidget {
  /// Single-date picker variant.
  const BTInputDate.single({
    this.label,
    this.placeholder,
    this.required = false,
    this.disabled = false,
    this.readOnly = false,
    this.errorText,
    this.value,
    this.onChanged,
    this.onClear,
    this.showType = BTCalendarShowType.modal,
    this.resetIcon,
    this.calendarOptions,
    this.locale = 'id',
    this.size = BTInputSize.normal,
    this.validator,
    super.key,
  })  : _isRange = false,
        rangeValue = null,
        onRangeChanged = null,
        rangeOptions = null,
        rangeValidator = null;

  /// Date-range picker variant.
  const BTInputDate.range({
    this.label,
    this.placeholder,
    this.required = false,
    this.disabled = false,
    this.readOnly = false,
    this.errorText,
    this.rangeValue,
    this.onRangeChanged,
    this.onClear,
    this.showType = BTCalendarShowType.modal,
    this.resetIcon,
    this.rangeOptions,
    this.locale = 'id',
    this.size = BTInputSize.normal,
    this.rangeValidator,
    super.key,
  })  : _isRange = true,
        value = null,
        onChanged = null,
        calendarOptions = null,
        validator = null;

  final bool _isRange;

  /// Label that floats to the top-left when focused or filled.
  final String? label;

  /// Hint shown inside the field when floating and no date is selected.
  final String? placeholder;

  /// Appends " *" (red) to [label] when true.
  final bool required;

  /// Disables all interaction and applies disabled visual state.
  final bool disabled;

  /// Blocks interaction but keeps normal (non-greyed) colors.
  final bool readOnly;

  /// When set, shows the error border and validation text.
  final String? errorText;

  // ── Single ──────────────────────────────────────────────────────────────────

  /// Currently selected date (single mode).
  final DateTime? value;

  /// Called when a date is confirmed. `null` means value was cleared.
  final ValueChanged<DateTime?>? onChanged;

  /// Options forwarded to [BTCalendar.show].
  final BTCalendarOptions? calendarOptions;

  /// Validator for [Form.validate] integration.
  final FormFieldValidator<DateTime?>? validator;

  // ── Range ───────────────────────────────────────────────────────────────────

  /// Currently selected date range (range mode).
  final DateTimeRange? rangeValue;

  /// Called when a range is confirmed.
  final ValueChanged<DateTimeRange?>? onRangeChanged;

  /// Options forwarded to [BTCalendar.showRange].
  final BTRangeCalendarOptions? rangeOptions;

  /// Validator for [Form.validate] integration (range mode).
  final FormFieldValidator<DateTimeRange?>? rangeValidator;

  // ── Shared ──────────────────────────────────────────────────────────────────

  /// Called when the × button is tapped (value cleared).
  final VoidCallback? onClear;

  /// Whether the calendar appears as a modal dialog or a bottom-sheet drawer.
  final BTCalendarShowType showType;

  /// Custom widget rendered as the reset/clear icon inside the calendar header.
  /// Falls back to the default refresh icon when null.
  final Widget? resetIcon;

  /// BCP-47 locale used for date formatting. `'id'` or `'en'`.
  final String locale;

  /// Field height variant — [BTInputSize.normal] (48 px) or [BTInputSize.small] (~40 px).
  final BTInputSize size;

  @override
  State<BTInputDate> createState() => _BTInputDateState();
}

class _BTInputDateState extends State<BTInputDate> {
  DateTime? _date;
  DateTimeRange? _range;

  /// True while the calendar picker is open — drives the active (blue) border.
  bool _isOpen = false;

  bool get _hasValue => widget._isRange ? _range != null : _date != null;
  bool get _isFloating => _hasValue || _isOpen;

  String get _formatHint => widget._isRange
      ? 'DD MMM YYYY - DD MMM YYYY'
      : 'DD MMM YYYY';

  String get _displayText {
    if (widget._isRange) {
      return _range == null
          ? ''
          : formatDateRange(_range!.start, _range!.end, widget.locale);
    }
    return _date == null ? '' : formatDate(_date, widget.locale);
  }

  @override
  void initState() {
    super.initState();
    _date = widget.value;
    _range = widget.rangeValue;
  }

  @override
  void didUpdateWidget(BTInputDate old) {
    super.didUpdateWidget(old);
    if (!widget._isRange && widget.value != old.value) _date = widget.value;
    if (widget._isRange && widget.rangeValue != old.rangeValue) {
      _range = widget.rangeValue;
    }
  }

  Future<void> _onTap() async {
    if (widget.disabled || widget.readOnly) return;
    setState(() => _isOpen = true);

    if (widget._isRange) {
      final opts = (widget.rangeOptions ?? const BTRangeCalendarOptions())
          .copyWith(
        initStartDate: _range?.start,
        initFinishDate: _range?.end,
      );
      final result = await BTCalendar.showRange(
        context,
        options: opts,
        type: widget.showType,
        showPresets: opts.showPresets,
        resetIcon: widget.resetIcon,
      );
      if (!mounted) return;
      setState(() {
        if (result != null) _range = result;
        _isOpen = false;
      });
      if (result != null) widget.onRangeChanged?.call(result);
    } else {
      final opts = (widget.calendarOptions ?? const BTCalendarOptions())
          .copyWith(initialDate: _date);
      final result = await BTCalendar.show(
        context,
        options: opts,
        type: widget.showType,
        showPresets: opts.showPresets,
        resetIcon: widget.resetIcon,
      );
      if (!mounted) return;
      setState(() {
        if (result != null) _date = result;
        _isOpen = false;
      });
      if (result != null) widget.onChanged?.call(result);
    }
  }

  void _onClear() {
    setState(() {
      _date = null;
      _range = null;
    });
    widget.onChanged?.call(null);
    widget.onRangeChanged?.call(null);
    widget.onClear?.call();
  }

  // ── Color helpers ────────────────────────────────────────────────────────────

  Color _borderColor(BTColorTheme c, {required bool hasError}) {
    if (widget.disabled) return c.border.primary;
    if (hasError) return c.ext.error;
    if (_isOpen) return c.brand.primary;
    return c.border.primary;
  }

  Color _labelColor(BTColorTheme c, {required bool hasError}) {
    if (widget.disabled) return c.text.disabled;
    if (hasError) return c.ext.error;
    return c.text.secondary;
  }

  // ── Build ────────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    if (widget.validator != null || widget.rangeValidator != null) {
      return FormField<String>(
        autovalidateMode: AutovalidateMode.disabled,
        validator: (_) => widget._isRange
            ? widget.rangeValidator?.call(_range)
            : widget.validator?.call(_date),
        builder: (field) =>
            _buildBody(context, errorText: widget.errorText ?? field.errorText),
      );
    }
    return _buildBody(context, errorText: widget.errorText);
  }

  Widget _buildBody(BuildContext context, {required String? errorText}) {
    final c = context.btColor;
    final hasError = errorText != null;
    final hasLabel = widget.label != null;
    final labelColor = _labelColor(c, hasError: hasError);
    final valueColor = widget.disabled ? c.text.disabled : c.text.primary;
    final iconColor = widget.disabled ? c.text.disabled : c.icon.primary;

    // Show × when the picker is open and there's a value to clear.
    final showClear = _isOpen && _hasValue && !widget.disabled;

    final isSmall = widget.size == BTInputSize.small;

    // Vertical padding: small uses 12px empty / 4px floating; normal uses 8px always.
    // When there is no label the container relies only on padding to center the text.
    final double vertPad;
    if (isSmall) {
      vertPad = hasLabel ? (_isFloating ? 4.0 : 12.0) : 12.0;
    } else {
      vertPad = hasLabel ? 8.0 : 16.0;
    }

    final field = AnimatedContainer(
      duration: const Duration(milliseconds: 150),
      curve: const Cubic(0.4, 0, 0.2, 1),
      constraints: isSmall
          ? const BoxConstraints()
          : const BoxConstraints(minHeight: 48),
      decoration: BoxDecoration(
        color: widget.disabled ? c.bg.subtle : c.bg.primary,
        border: Border.all(
          color: _borderColor(c, hasError: hasError),
          width: 1,
        ),
        borderRadius: BorderRadius.circular(BTRadius.sm),
      ),
      child: GestureDetector(
        behavior: HitTestBehavior.translucent,
        onTap: (widget.disabled || widget.readOnly) ? null : _onTap,
        child: Padding(
          padding: EdgeInsets.symmetric(horizontal: 8.0, vertical: vertPad),
          child: Row(
            crossAxisAlignment: CrossAxisAlignment.center,
            children: [
              Icon(Icons.calendar_month, size: 16, color: iconColor),
              SizedBox(width: 8.0),
              Expanded(
                child: _buildContent(
                  c,
                  labelColor: labelColor,
                  valueColor: valueColor,
                  hasError: hasError,
                  isSmall: isSmall,
                ),
              ),
              ClipRect(
                child: AnimatedAlign(
                  duration: const Duration(milliseconds: 150),
                  curve: const Cubic(0.4, 0, 0.2, 1),
                  alignment: AlignmentDirectional.centerEnd,
                  widthFactor: showClear ? 1.0 : 0.0,
                  child: Row(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      SizedBox(width: 8.0),

                      GestureDetector(
                        onTap: _onClear,
                        child: Icon(
                          Icons.cancel,
                          size: 16,
                          color: c.icon.primary,
                        ),
                      ),
                    ],
                  ),
                ),
              ),
            ],
          ),
        ),
      ),
    );

    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        field,
        if (hasError)
          Padding(
            padding: EdgeInsets.only(top: 4.0),
            child: Text(
              errorText,
              style: TextStyle(
                fontFamily: BTTypography.fontFamily,
                fontSize: 12.0,
                fontWeight: FontWeight.w500,
                height: 4 / 3,
                color: c.ext.error,
              ),
            ),
          ),
      ],
    );
  }

  Widget _buildContent(
    BTColorTheme c, {
    required Color labelColor,
    required Color valueColor,
    required bool hasError,
    required bool isSmall,
  }) {
    final valueFontSize = isSmall ? 12.0 : 14.0;

    // No label: single line, value or format hint.
    if (widget.label == null) {
      final text = _displayText.isEmpty ? _formatHint : _displayText;
      return Text(
        text,
        maxLines: 1,
        overflow: TextOverflow.ellipsis,
        style: TextStyle(
          fontFamily: BTTypography.fontFamily,
          fontSize: valueFontSize,
          fontWeight: FontWeight.w500,
          height: 8 / 7,
          color: _displayText.isEmpty ? c.text.tertiary : valueColor,
        ),
      );
    }

    // With label: floating label + value text (same pattern as BTInput).
    // Not floating → label text acts as the placeholder hint.
    // Floating   → label slides up and value text shows the selected date.
    final displayValue = _isFloating ? _displayText : widget.label!;
    final displayColor = _isFloating ? valueColor : labelColor;

    final labelWidget = ClipRect(
      child: AnimatedAlign(
        duration: const Duration(milliseconds: 150),
        curve: const Cubic(0.4, 0, 0.2, 1),
        alignment: AlignmentDirectional.topStart,
        heightFactor: _isFloating ? 1.0 : 0.0,
        child: Text.rich(
          TextSpan(
            children: [
              TextSpan(text: widget.label),
              if (widget.required)
                TextSpan(
                  text: ' *',
                  style: TextStyle(color: c.ext.error),
                ),
            ],
          ),
          maxLines: 1,
          overflow: TextOverflow.ellipsis,
          style: TextStyle(
            fontFamily: BTTypography.fontFamily,
            fontSize: 12.0,
            fontWeight: FontWeight.w500,
            height: 4 / 3,
            color: labelColor,
          ),
        ),
      ),
    );

    final valueWidget = Text(
      displayValue,
      maxLines: 1,
      overflow: TextOverflow.ellipsis,
      style: TextStyle(
        fontFamily: BTTypography.fontFamily,
        fontSize: valueFontSize,
        fontWeight: FontWeight.w500,
        height: 8 / 7,
        color: displayColor,
      ),
    );

    // Small: natural Column height (no fixed SizedBox). Vertical padding on the
    // outer container drives the overall field height (~40 px) instead.
    if (isSmall) {
      return Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [labelWidget, valueWidget],
      );
    }

    // Normal: SizedBox(32) pins content so the field stays exactly 48 px
    // (8 px top pad + 32 px content + 8 px bottom pad).
    return SizedBox(
      height: 32.0,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          labelWidget,
          Expanded(
            child: Align(
              alignment: AlignmentDirectional.centerStart,
              child: valueWidget,
            ),
          ),
        ],
      ),
    );
  }
}

/// BTInputDropdown — tap-to-open single-select input field.
///
/// Opens [BTDropdownList] directly below the field, matching its width.
/// Selecting an item closes the dropdown and updates the displayed value.
///
/// ## Usage
/// ```dart
/// BTInputDropdown<String>(
///   label: 'Framework',
///   required: true,
///   value: _value,
///   items: const [
///     BTDropdownItem(value: 'flutter', label: 'Flutter'),
///     BTDropdownItem(value: 'react',   label: 'React'),
///     BTDropdownItem(value: 'vue',     label: 'Vue'),
///   ],
///   onChanged: (v) => setState(() => _value = v),
///   onClear: () => setState(() => _value = null),
/// )
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import '../../dropdown-list/dropdown_list.types.dart';
import '../../dropdown-list/dropdown_list.widget.dart';
import 'package:btech_ui/src/components/molecules/input/input.types.dart';
import 'package:flutter/material.dart';

class BTInputDropdown<T> extends StatefulWidget {
  const BTInputDropdown({
    required this.items,
    this.label,
    this.placeholder,
    this.required = false,
    this.disabled = false,
    this.readOnly = false,
    this.errorText,
    this.value,
    this.hasSearch = false,
    this.itemsFilter,
    this.emptyLabel = 'No result found.',
    this.prefix,
    this.size = BTInputSize.normal,
    this.onChanged,
    this.onClear,
    this.validator,
    super.key,
  });

  /// Items shown in [BTDropdownList].
  final List<BTDropdownItem<T>> items;

  /// Label that floats to the top-left when focused or filled.
  final String? label;

  /// Hint text shown as center text when no label is provided and nothing
  /// is selected.
  final String? placeholder;

  /// Appends " *" (red) to [label] when true.
  final bool required;

  /// Disables all interaction and applies disabled visual state.
  final bool disabled;

  /// Blocks interaction but keeps normal (non-greyed) colours.
  final bool readOnly;

  /// When set, shows the error border and validation text below the field.
  final String? errorText;

  /// Currently selected value.
  final T? value;

  /// Show a [BTInputSearch] at the top of the dropdown list.
  final bool hasSearch;

  /// Custom filter applied when [hasSearch] is true and the user types a query.
  /// Receives the full [items] list and the current query string; returns the
  /// filtered subset to display.
  ///
  /// When null, defaults to a case-insensitive [String.contains] match on
  /// [BTDropdownItem.label].
  ///
  /// ```dart
  /// itemsFilter: (items, query) => items
  ///     .where((i) =>
  ///         i.label.toLowerCase().contains(query) ||
  ///         i.value.toString().toLowerCase().startsWith(query))
  ///     .toList(),
  /// ```
  final List<BTDropdownItem<T>> Function(
    List<BTDropdownItem<T>> items,
    String query,
  )? itemsFilter;

  /// Text shown beneath the empty-state illustration.
  final String emptyLabel;

  /// Optional widget prepended before the label/value (left icon slot).
  final Widget? prefix;

  /// Called when an item is selected. `null` is emitted when cleared.
  final ValueChanged<T?>? onChanged;

  /// Called when the × button clears the selection.
  final VoidCallback? onClear;

  /// Validator for [Form.validate] integration.
  final FormFieldValidator<T?>? validator;

  /// Field height variant — [BTInputSize.normal] (48 px) or [BTInputSize.small] (~40 px).
  final BTInputSize size;

  @override
  State<BTInputDropdown<T>> createState() => _BTInputDropdownState<T>();
}

class _BTInputDropdownState<T> extends State<BTInputDropdown<T>> {
  final _overlayController = OverlayPortalController();
  final _fieldKey = GlobalKey();

  T? _selectedValue;
  String _searchQuery = '';
  bool _isOpen = false;
  // Captured by LayoutBuilder — used to size the overlay list.
  double _fieldWidth = 210;

  bool get _hasValue => _selectedValue != null;
  bool get _isFloating => _hasValue;

  String get _displayText {
    if (_selectedValue == null) return '';
    final matches = widget.items.where((i) => i.value == _selectedValue);
    return matches.isEmpty ? '' : matches.first.label;
  }

  @override
  void initState() {
    super.initState();
    _selectedValue = widget.value;
  }

  @override
  void didUpdateWidget(BTInputDropdown<T> old) {
    super.didUpdateWidget(old);
    if (widget.value != old.value) _selectedValue = widget.value;
  }

  void _open() {
    if (_isOpen || widget.disabled || widget.readOnly) return;
    setState(() {
      _isOpen = true;
      _searchQuery = '';
    });
    _overlayController.show();
  }

  void _close() {
    if (!_isOpen) return;
    _overlayController.hide();
    setState(() => _isOpen = false);
  }

  void _toggle() => _isOpen ? _close() : _open();

  void _handleSelect(T value) {
    setState(() => _selectedValue = value);
    widget.onChanged?.call(value);
    _close();
  }

  void _onClear() {
    setState(() => _selectedValue = null);
    widget.onChanged?.call(null);
    widget.onClear?.call();
    _close();
  }

  List<BTDropdownItem<T>> get _filteredItems {
    final List<BTDropdownItem<T>> source;
    if (!widget.hasSearch || _searchQuery.isEmpty) {
      source = widget.items;
    } else if (widget.itemsFilter != null) {
      source = widget.itemsFilter!(widget.items, _searchQuery);
    } else {
      final q = _searchQuery.toLowerCase();
      source = widget.items
          .where((i) => i.label.toLowerCase().contains(q))
          .toList();
    }
    return source
        .map(
          (i) => BTDropdownItem<T>(
            value: i.value,
            label: i.label,
            disabled: i.disabled,
            avatar: i.avatar,
            checked: i.value == _selectedValue,
          ),
        )
        .toList();
  }

  // ── Color helpers ────────────────────────────────────────────────────────────

  Color _borderColor(BTColorTheme c, {required bool hasError}) {
    if (widget.disabled) return c.border.primary;
    if (hasError) return c.ext.error;
    if (_isOpen) return c.brand.primary;
    return c.border.primary;
  }

  Color _labelColor(BTColorTheme c, {required bool hasError}) {
    if (widget.disabled) return c.text.disabled;
    if (hasError) return c.ext.error;
    return c.text.secondary;
  }

  // ── Build ────────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    if (widget.validator != null) {
      return FormField<T?>(
        autovalidateMode: AutovalidateMode.disabled,
        validator: (_) => widget.validator?.call(_selectedValue),
        builder: (field) =>
            _buildBody(context, errorText: widget.errorText ?? field.errorText),
      );
    }
    return _buildBody(context, errorText: widget.errorText);
  }

  Widget _buildBody(BuildContext context, {required String? errorText}) {
    final c = context.btColor;
    final hasError = errorText != null;
    final hasLabel = widget.label != null;
    final labelColor = _labelColor(c, hasError: hasError);
    final valueColor = widget.disabled ? c.text.disabled : c.text.primary;
    final iconColor = widget.disabled ? c.text.disabled : c.icon.primary;

    final isSmall = widget.size == BTInputSize.small;

    final double vertPad;
    if (isSmall) {
      vertPad = hasLabel ? (_isFloating ? 4.0 : 12.0) : 12.0;
    } else {
      vertPad = hasLabel ? 8.0 : 16.0;
    }

    // × shown when open, has value, not disabled, and no error.
    // Figma Error-Filled (open + error) shows only chevron-up, no ×.
    final showClear = _isOpen && _hasValue && !widget.disabled && !hasError;

    final field = LayoutBuilder(
      builder: (ctx, constraints) {
        _fieldWidth = constraints.maxWidth;
        return KeyedSubtree(
          key: _fieldKey,
          child: OverlayPortal(
            controller: _overlayController,
            overlayChildBuilder: (_) {
              // Measure field position at render time for reliable auto-flip.
              final box = _fieldKey.currentContext?.findRenderObject() as RenderBox?;
              if (box == null || !box.hasSize) return const SizedBox.shrink();

              final fieldPos    = box.localToGlobal(Offset.zero);
              final fieldHeight = box.size.height;
              final screen      = MediaQuery.of(context).size;
              const gap         = 4.0;
              const maxPanelH   = 240.0;

              final spaceBelow = screen.height - (fieldPos.dy + fieldHeight) - gap;
              final spaceAbove = fieldPos.dy - gap;
              final showAbove  = spaceBelow < maxPanelH && spaceAbove > spaceBelow;

              final effectiveMaxH = showAbove
                  ? spaceAbove.clamp(80.0, maxPanelH)
                  : spaceBelow.clamp(80.0, maxPanelH);

              final isRtl = Directionality.of(context) == TextDirection.rtl;

              return Stack(
                children: [
                  Positioned(
                    left:   isRtl ? null : fieldPos.dx,
                    right:  isRtl ? screen.width - fieldPos.dx - _fieldWidth : null,
                    top:    showAbove ? null : fieldPos.dy + fieldHeight + gap,
                    bottom: showAbove ? screen.height - fieldPos.dy + gap : null,
                    width:  _fieldWidth,
                    child: TapRegion(
                      groupId: _fieldKey,
                      onTapOutside: (_) => _close(),
                      child: ConstrainedBox(
                        constraints: BoxConstraints(maxHeight: effectiveMaxH),
                        child: BTDropdownList<T>(
                          items:       _filteredItems,
                          hasSearch:   widget.hasSearch,
                          searchQuery: _searchQuery,
                          emptyLabel:  widget.emptyLabel,
                          width:       _fieldWidth,
                          onSearch:    widget.hasSearch
                              ? (q) => setState(() => _searchQuery = q)
                              : null,
                          onSelect:    _handleSelect,
                        ),
                      ),
                    ),
                  ),
                ],
              );
            },
            child: TapRegion(
              groupId: _fieldKey,
              onTapOutside: (_) => _close(),
              child: GestureDetector(
                behavior: HitTestBehavior.translucent,
                onTap: (widget.disabled || widget.readOnly) ? null : _toggle,
                child: AnimatedContainer(
                duration: const Duration(milliseconds: 150),
                curve: const Cubic(0.4, 0, 0.2, 1),
                constraints: isSmall
                    ? const BoxConstraints()
                    : const BoxConstraints(minHeight: 48),
                decoration: BoxDecoration(
                  color: widget.disabled ? c.bg.subtle : c.bg.primary,
                  border: Border.all(
                    color: _borderColor(c, hasError: hasError),
                    width: 1,
                  ),
                  borderRadius: BorderRadius.circular(BTRadius.sm),
                ),
                padding: EdgeInsets.symmetric(horizontal: 8.0, vertical: vertPad),
                child: Row(
                  crossAxisAlignment: CrossAxisAlignment.center,
                  children: [
                    if (widget.prefix != null) ...[
                      widget.prefix!,
                      SizedBox(width: 8.0),
                    ],
                    Expanded(
                      child: _buildContent(
                        c,
                        labelColor: labelColor,
                        valueColor: valueColor,
                        hasError: hasError,
                        isSmall: isSmall,
                      ),
                    ),
                    ClipRect(
                      child: AnimatedAlign(
                        duration: const Duration(milliseconds: 150),
                        curve: const Cubic(0.4, 0, 0.2, 1),
                        alignment: AlignmentDirectional.centerEnd,
                        widthFactor: showClear ? 1.0 : 0.0,
                        child: Row(
                          mainAxisSize: MainAxisSize.min,
                          children: [
                            SizedBox(width: 8.0),
                            GestureDetector(
                              onTap: _onClear,
                              child: Icon(
                                Icons.cancel,
                                size: 16,
                                color: c.icon.primary,
                              ),
                            ),
                          ],
                        ),
                      ),
                    ),
                    SizedBox(width: 8.0),
                    Icon(
                      _isOpen
                          ? Icons.keyboard_arrow_up
                          : Icons.keyboard_arrow_down,
                      size: 16,
                      color: iconColor,
                    ),
                  ],
                ),
                ),
              ),
            ),
          ),
        );
      },
    );

    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        field,
        if (hasError)
          Padding(
            padding: EdgeInsets.only(top: 4.0),
            child: Text(
              errorText,
              style: TextStyle(
                fontFamily: BTTypography.fontFamily,
                fontSize: 12.0,
                fontWeight: FontWeight.w500,
                height: 4 / 3,
                color: c.ext.error,
              ),
            ),
          ),
      ],
    );
  }

  Widget _buildContent(
    BTColorTheme c, {
    required Color labelColor,
    required Color valueColor,
    required bool hasError,
    required bool isSmall,
  }) {
    final valueFontSize = isSmall ? 12.0 : 14.0;

    if (widget.label == null) {
      final text =
          _displayText.isEmpty ? (widget.placeholder ?? '') : _displayText;
      return Text(
        text,
        maxLines: 1,
        overflow: TextOverflow.ellipsis,
        style: TextStyle(
          fontFamily: BTTypography.fontFamily,
          fontSize: valueFontSize,
          fontWeight: FontWeight.w500,
          height: 8 / 7,
          color: _displayText.isEmpty ? c.text.tertiary : valueColor,
        ),
      );
    }

    // Label acts as hint when not floating — same pattern as BTInput family.
    final displayValue = _isFloating ? _displayText : widget.label!;
    final displayColor = _isFloating ? valueColor : labelColor;

    final labelWidget = ClipRect(
      child: AnimatedAlign(
        duration: const Duration(milliseconds: 150),
        curve: const Cubic(0.4, 0, 0.2, 1),
        alignment: AlignmentDirectional.topStart,
        heightFactor: _isFloating ? 1.0 : 0.0,
        child: Text.rich(
          TextSpan(
            children: [
              TextSpan(text: widget.label),
              if (widget.required)
                TextSpan(
                  text: ' *',
                  style: TextStyle(color: c.ext.error),
                ),
            ],
          ),
          maxLines: 1,
          overflow: TextOverflow.ellipsis,
          style: TextStyle(
            fontFamily: BTTypography.fontFamily,
            fontSize: 12.0,
            fontWeight: FontWeight.w500,
            height: 4 / 3,
            color: labelColor,
          ),
        ),
      ),
    );

    final valueWidget = Text(
      displayValue,
      maxLines: 1,
      overflow: TextOverflow.ellipsis,
      style: TextStyle(
        fontFamily: BTTypography.fontFamily,
        fontSize: valueFontSize,
        fontWeight: FontWeight.w500,
        height: 8 / 7,
        color: displayColor,
      ),
    );

    // Small: natural Column height — outer padding drives the ~40 px field height.
    if (isSmall) {
      return Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [labelWidget, valueWidget],
      );
    }

    // Normal: SizedBox(32) pins content so the field stays exactly 48 px.
    // Expanded + Align(centerLeft) vertically centers the value when not floating.
    return SizedBox(
      height: 32.0,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          labelWidget,
          Expanded(
            child: Align(
              alignment: AlignmentDirectional.centerStart,
              child: valueWidget,
            ),
          ),
        ],
      ),
    );
  }
}

import 'package:flutter/foundation.dart';

/// Data class for a single unit option in [BTInputFieldUnit].
///
/// ```dart
/// const currencies = [
///   BTInputFieldUnitOption(label: 'IDR', value: 'IDR'),
///   BTInputFieldUnitOption(label: 'USD', value: 'USD'),
///   BTInputFieldUnitOption(label: 'EUR', value: 'EUR'),
/// ];
/// ```
@immutable
class BTInputFieldUnitOption {
  const BTInputFieldUnitOption({
    required this.label,
    required this.value,
  });

  /// Short display text shown in the left dropdown pill and the overlay list.
  /// E.g. "IDR", "USD", "kg", "%".
  final String label;

  /// Unique identifier for this unit. Used for equality checks and as the
  /// key passed to [BTInputFieldUnit.formattersBuilder].
  final String value;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      (other is BTInputFieldUnitOption && other.value == value);

  @override
  int get hashCode => value.hashCode;

  @override
  String toString() =>
      'BTInputFieldUnitOption(label: $label, value: $value)';
}

/// BTInputFieldUnit — two-panel input: unit selector dropdown (left) +
/// value text field (right). Each panel has its own focus/active state.
///
/// When the selected unit changes, the current value is stripped of its old
/// formatting and re-formatted with the new unit's formatters automatically —
/// the user never has to re-type the value.
///
/// ## Basic usage (currency)
///
/// ```dart
/// BTInputFieldUnit(
///   units: const [
///     BTInputFieldUnitOption(label: 'IDR', value: 'IDR'),
///     BTInputFieldUnitOption(label: 'USD', value: 'USD'),
///     BTInputFieldUnitOption(label: 'EUR', value: 'EUR'),
///   ],
///   unitLabel: 'Currency',
///   label: 'Amount',
///   initialUnit: BTInputFieldUnitOption(label: 'IDR', value: 'IDR'),
///   keyboardType: TextInputType.number,
///   onUnitChanged: (u) => setState(() => _unit = u),
///   onChanged: (v) => setState(() => _value = v),
/// )
/// ```
///
/// ## With thousands-separator formatting
///
/// ```dart
/// BTInputFieldUnit(
///   units: const [
///     BTInputFieldUnitOption(label: 'IDR', value: 'IDR'),
///     BTInputFieldUnitOption(label: 'USD', value: 'USD'),
///   ],
///   unitLabel: 'Currency',
///   label: 'Amount',
///   initialUnit: BTInputFieldUnitOption(label: 'IDR', value: 'IDR'),
///   keyboardType: TextInputType.number,
///   formattersBuilder: (unit) => switch (unit?.value) {
///     // IDR: period as thousands separator → 1.000.000
///     'IDR' => [
///         FilteringTextInputFormatter.digitsOnly,
///         _ThousandsSeparatorFormatter(separator: '.'),
///       ],
///     // USD/EUR: comma as thousands separator → 1,000,000
///     _ => [
///         FilteringTextInputFormatter.digitsOnly,
///         _ThousandsSeparatorFormatter(separator: ','),
///       ],
///   },
///   onUnitChanged: (u) => setState(() => _unit = u),
///   onChanged: (v) => setState(() => _value = v),
/// )
/// ```
///
/// ## With phone-number pattern formatting (non-numeric)
///
/// ```dart
/// BTInputFieldUnit(
///   units: const [
///     BTInputFieldUnitOption(label: '+62', value: '+62'),
///     BTInputFieldUnitOption(label: '+1',  value: '+1'),
///     BTInputFieldUnitOption(label: '+65', value: '+65'),
///   ],
///   unitLabel: 'Code',
///   label: 'Phone number',
///   initialUnit: BTInputFieldUnitOption(label: '+62', value: '+62'),
///   keyboardType: TextInputType.phone,
///   formattersBuilder: (unit) => switch (unit?.value) {
///     '+62' => [
///         FilteringTextInputFormatter.digitsOnly,
///         _PhoneFormatter('XXX-XXXX-XXXX'),     // 812-3456-7890
///       ],
///     '+1'  => [
///         FilteringTextInputFormatter.digitsOnly,
///         _PhoneFormatter('(XXX) XXX-XXXX'),    // (555) 123-4567
///       ],
///     '+65' => [
///         FilteringTextInputFormatter.digitsOnly,
///         _PhoneFormatter('XXXX XXXX'),          // 9123 4567
///       ],
///     _ => [FilteringTextInputFormatter.digitsOnly],
///   },
///   onUnitChanged: (u) => setState(() => _unit = u),
///   onChanged: (v) => setState(() => _value = v),
/// )
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import '../../dropdown-list/dropdown_list.types.dart';
import '../../dropdown-list/dropdown_list.widget.dart'
    as atom;
import 'package:btech_ui/src/components/molecules/input/field_unit/input_field_unit.types.dart';
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

// ─── Constants ──────────────────────────────────────────────────────────────


// ─── Widget ─────────────────────────────────────────────────────────────────

class BTInputFieldUnit extends StatefulWidget {
  /// Creates a BTInputFieldUnit.
  const BTInputFieldUnit({
    required this.units,
    super.key,
    this.unitLabel,
    this.selectedUnit,
    this.initialUnit,
    this.onUnitChanged,
    this.label,
    this.value,
    this.onChanged,
    this.formattersBuilder,
    this.keyboardType,
    this.hintText,
    this.errorText,
    this.helperText,
    this.disabled = false,
    this.required = false,
    this.validator,
  });

  // ── Left dropdown ────────────────────────────────────────────────────────

  /// Options shown in the unit selector dropdown.
  final List<BTInputFieldUnitOption> units;

  /// Floating label above the selected unit text (e.g. "Currency").
  final String? unitLabel;

  /// Controlled selected unit. When provided, internal selection is ignored.
  final BTInputFieldUnitOption? selectedUnit;

  /// Initial unit shown before any selection (uncontrolled mode).
  final BTInputFieldUnitOption? initialUnit;

  /// Called when the user picks a different unit.
  final ValueChanged<BTInputFieldUnitOption>? onUnitChanged;

  // ── Right text field ─────────────────────────────────────────────────────

  /// Floating label for the value text field (e.g. "Amount").
  final String? label;

  /// Controlled text value. Synced to the internal controller on each build.
  final String? value;

  /// Called whenever the typed value changes.
  final ValueChanged<String>? onChanged;

  /// Returns [TextInputFormatter] list to apply for the given unit.
  /// Called when the selected unit changes. Returning an empty list removes
  /// all formatters.
  ///
  /// Example — digits-only with thousands separator:
  /// ```dart
  /// formattersBuilder: (unit) => [
  ///   FilteringTextInputFormatter.digitsOnly,
  ///   _ThousandsSeparatorFormatter(
  ///     unit?.value == 'USD' ? ',' : '.',
  ///   ),
  /// ],
  /// ```
  final List<TextInputFormatter> Function(BTInputFieldUnitOption? unit)?
      formattersBuilder;

  /// Keyboard type for the value field. Defaults to [TextInputType.text].
  final TextInputType? keyboardType;

  /// Placeholder text shown when the right field is empty and unfocused.
  final String? hintText;

  // ── Shared ───────────────────────────────────────────────────────────────

  /// When set, shows a red border and this text below the component.
  final String? errorText;

  /// Helper text shown below the component in the non-error state.
  final String? helperText;

  /// Disables both panels.
  final bool disabled;

  /// Appends a red asterisk to labels.
  final bool required;

  /// Form validator (wraps component in [FormField] for [Form.validate()]).
  final String? Function(String?)? validator;

  @override
  State<BTInputFieldUnit> createState() => _BTInputFieldUnitState();
}

class _BTInputFieldUnitState extends State<BTInputFieldUnit> {
  // ── Overlay ──────────────────────────────────────────────────────────────
  final _overlayController = OverlayPortalController();
  final _unitPanelKey = GlobalKey();
  static const _kMinSpaceBelow = 180.0;
  bool _dropdownAbove = false;
  double _overlayTop = 0;
  double _overlayBottom = 0;
  double _overlayLeft = 0;
  double _overlayWidth = 0;
  double _overlayMaxHeight = 300;
  bool _isDropdownOpen = false;

  // ── Text field ───────────────────────────────────────────────────────────
  final _focusNode = FocusNode();
  late final TextEditingController _textController;
  bool _isFocused = false;

  // ── Unit selection ───────────────────────────────────────────────────────
  BTInputFieldUnitOption? _internalUnit;

  BTInputFieldUnitOption? get _effectiveUnit =>
      widget.selectedUnit ?? _internalUnit;

  bool get _hasValue => _textController.text.isNotEmpty;
  bool get _isValueFloating => _hasValue || _isFocused;
  bool get _isUnitFloating => _effectiveUnit != null;

  @override
  void initState() {
    super.initState();
    // Default is no selection — caller must provide initialUnit explicitly.
    _internalUnit = widget.initialUnit;
    _textController = TextEditingController(text: widget.value ?? '');
    _focusNode.addListener(_onFocusChange);
  }

  @override
  void didUpdateWidget(BTInputFieldUnit old) {
    super.didUpdateWidget(old);
    if (widget.value != null && widget.value != _textController.text) {
      _textController.text = widget.value!;
    }
  }

  @override
  void dispose() {
    _focusNode
      ..removeListener(_onFocusChange)
      ..dispose();
    _textController.dispose();
    super.dispose();
  }

  void _onFocusChange() {
    setState(() => _isFocused = _focusNode.hasFocus);
  }

  // ── Overlay position ─────────────────────────────────────────────────────

  void _syncOverlayPosition() {
    final box =
        _unitPanelKey.currentContext?.findRenderObject() as RenderBox?;
    if (box == null || !box.attached) return;
    final origin = box.localToGlobal(Offset.zero);
    final screenHeight = MediaQuery.sizeOf(context).height;
    final fieldBottom = origin.dy + box.size.height;
    final spaceBelow = screenHeight - fieldBottom;

    _dropdownAbove = spaceBelow < _kMinSpaceBelow;
    _overlayLeft = origin.dx;
    _overlayWidth = box.size.width;
    if (_dropdownAbove) {
      _overlayBottom = screenHeight - origin.dy + 4;
      _overlayMaxHeight = origin.dy - 8;
    } else {
      _overlayTop = fieldBottom + 4;
      _overlayMaxHeight = spaceBelow - 8;
    }
  }

  // ── Dropdown ─────────────────────────────────────────────────────────────

  void _openDropdown() {
    if (_isDropdownOpen || widget.disabled) return;
    _syncOverlayPosition();
    setState(() => _isDropdownOpen = true);
    _overlayController.show();
  }

  void _closeDropdown() {
    if (!_isDropdownOpen) return;
    _overlayController.hide();
    setState(() => _isDropdownOpen = false);
  }

  void _toggleDropdown() =>
      _isDropdownOpen ? _closeDropdown() : _openDropdown();

  void _selectUnit(BTInputFieldUnitOption unit) {
    _closeDropdown();
    if (unit == _effectiveUnit) return;

    // Strip only the characters that formatters INJECT as decoration
    // (thousands separators, phone-pattern punctuation, spaces, slashes).
    // Alphanumeric characters, dots, underscores, hyphens, and @ are kept
    // so text-based formats (usernames, domains) survive a unit switch.
    final raw = _textController.text
        .replaceAll(RegExp(r'[\s,;()+\/\\]'), '');

    // Run the raw value through the new unit's formatters so the display
    // updates immediately without the user needing to re-type.
    var next = TextEditingValue(
      text: raw,
      selection: TextSelection.collapsed(offset: raw.length),
    );
    final newFormatters =
        widget.formattersBuilder?.call(unit) ?? const <TextInputFormatter>[];
    for (final f in newFormatters) {
      next = f.formatEditUpdate(TextEditingValue.empty, next);
    }

    setState(() {
      _internalUnit = unit;
      _textController.value = next;
    });
    widget.onUnitChanged?.call(unit);
    widget.onChanged?.call(_textController.text);
  }

  /// Clears the unit selection back to "no selection".
  /// Keeps the typed value but strips formatting so it reads as raw input.
  void _clearUnit() {
    _closeDropdown();
    final raw = _textController.text
        .replaceAll(RegExp(r'[\s,;()+\/\\]'), '');
    setState(() {
      _internalUnit = null;
      _textController.text = raw;
    });
    widget.onChanged?.call(raw);
  }

  /// Clears the right value field, mirroring base BTInput clear behaviour.
  void _clearValue() {
    setState(() => _textController.clear());
    widget.onChanged?.call('');
  }

  // ── Colours ──────────────────────────────────────────────────────────────

  Color _borderColor(
    BTColorTheme c, {
    required bool hasError,
    required bool isActive,
  }) {
    if (widget.disabled) return c.border.primary;
    if (hasError) return c.ext.error;
    if (isActive) return c.brand.primary;
    return c.border.primary;
  }

  Color _labelColor(BTColorTheme c, {required bool hasError}) {
    if (widget.disabled) return c.text.primary;
    if (hasError) return c.ext.error;
    return c.text.secondary;
  }

  // ── Build helpers ─────────────────────────────────────────────────────────

  Widget _floatingLabel({
    required String text,
    required bool isFloating,
    required Color color,
    bool appendAsterisk = false,
  }) {
    return ClipRect(
      child: AnimatedAlign(
        duration: const Duration(milliseconds: 150),
        curve: const Cubic(0.4, 0, 0.2, 1),
        alignment: AlignmentDirectional.topStart,
        heightFactor: isFloating ? 1.0 : 0.0,
        child: Text.rich(
          TextSpan(
            children: [
              TextSpan(text: text),
              if (appendAsterisk && widget.required)
                const TextSpan(text: ' *'),
            ],
          ),
          maxLines: 1,
          overflow: TextOverflow.ellipsis,
          strutStyle: StrutStyle(
            fontFamily: BTTypography.fontFamily,
            fontSize: 12.0,
            height: 4 / 3,
            forceStrutHeight: true,
          ),
          style: TextStyle(
            fontFamily: BTTypography.fontFamily,
            fontSize: 12.0,
            fontWeight: FontWeight.w500,
            height: 4 / 3,
            letterSpacing: 0,
            color: color,
          ),
        ),
      ),
    );
  }

  // ── Left unit panel ───────────────────────────────────────────────────────

  Widget _buildUnitPanel(BTColorTheme c, {required bool hasError}) {
    final labelColor = _labelColor(c, hasError: hasError);
    final iconColor =
        widget.disabled ? c.text.disabled : c.text.secondary;
    final border = _borderColor(
      c,
      hasError: hasError,
      isActive: _isDropdownOpen,
    );

    return GestureDetector(
      onTap: widget.disabled ? null : _toggleDropdown,
      child: Container(
        key: _unitPanelKey,
        // No fixed width — panel sizes to its content + padding.
        height: 48.0,
        padding: EdgeInsets.symmetric(horizontal: BTSpacing.sm),
        decoration: BoxDecoration(
          color: widget.disabled ? c.bg.subtle : c.bg.primary,
          border: Border.all(color: border),
          borderRadius: BorderRadius.circular(BTRadius.sm),
        ),
        child: Row(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.center,
          children: [
            // Column shrink-wraps to text width — no Expanded needed since
            // the Container has no fixed width and sizes to its content.
            Column(
              mainAxisSize: MainAxisSize.min,
              mainAxisAlignment: MainAxisAlignment.center,
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                if (widget.unitLabel != null)
                  _floatingLabel(
                    text: widget.unitLabel!,
                    isFloating: _isUnitFloating,
                    color: labelColor,
                    appendAsterisk: true,
                  ),
                Text(
                  _isUnitFloating
                      ? (_effectiveUnit?.label ?? '')
                      : (widget.unitLabel ?? ''),
                  style: TextStyle(
                    fontFamily: BTTypography.fontFamily,
                    fontSize: 14.0,
                    fontWeight: FontWeight.w500,
                    height: 16 / 14,
                    letterSpacing: 0,
                    color: _isUnitFloating
                        ? (widget.disabled
                            ? c.text.disabled
                            : c.text.primary)
                        : labelColor,
                  ),
                ),
              ],
            ),
            SizedBox(width: 4.0),
            // Cancel clears the unit selection; only shown when open.
            if (_isDropdownOpen && !widget.disabled)
              GestureDetector(
                onTap: _clearUnit,
                child: Icon(Icons.cancel, size: 16, color: iconColor),
              ),
            Icon(
              _isDropdownOpen
                  ? Icons.keyboard_arrow_up
                  : Icons.keyboard_arrow_down,
              size: 16,
              color: iconColor,
            ),
          ],
        ),
      ),
    );
  }

  // ── Right value field ─────────────────────────────────────────────────────

  Widget _buildValueField(BTColorTheme c, {required bool hasError}) {
    final labelColor = _labelColor(c, hasError: hasError);
    final border =
        _borderColor(c, hasError: hasError, isActive: _isFocused);
    final formatters =
        widget.formattersBuilder?.call(_effectiveUnit) ?? const [];

    // Mirror base BTInput layout:
    //   vertPad = 8 (label present) keeps container at 48px:
    //     8 (top) + 32 (SizedBox content) + 8 (bottom) = 48px
    //   When not floating: label animates to height=0, TextField fills all 32px
    //     and label text is shown as hintText at 14px (acts as placeholder).
    //   When floating: label = 16px, TextField = remaining 16px.
    final labelWidget = ClipRect(
      child: AnimatedAlign(
        duration: const Duration(milliseconds: 150),
        curve: const Cubic(0.4, 0, 0.2, 1),
        alignment: AlignmentDirectional.topStart,
        heightFactor: _isValueFloating ? 1.0 : 0.0,
        child: Text.rich(
          TextSpan(
            children: [
              if (widget.label != null) TextSpan(text: widget.label),
              if (widget.required && widget.label != null)
                TextSpan(
                  text: ' *',
                  style: TextStyle(color: c.ext.error),
                ),
            ],
          ),
          maxLines: 1,
          overflow: TextOverflow.ellipsis,
          strutStyle: StrutStyle(
            fontFamily: BTTypography.fontFamily,
            fontSize: 12.0,
            height: 4 / 3,
            forceStrutHeight: true,
          ),
          style: TextStyle(
            fontFamily: BTTypography.fontFamily,
            fontSize: 12.0,
            fontWeight: FontWeight.w500,
            height: 4 / 3,
            letterSpacing: 0,
            color: labelColor,
          ),
        ),
      ),
    );

    final textField = TextField(
      // Rebuild with new formatters when unit changes.
      key: ValueKey(_effectiveUnit?.value ?? '_none'),
      controller: _textController,
      focusNode: _focusNode,
      enabled: !widget.disabled,
      keyboardType: widget.keyboardType ?? TextInputType.text,
      inputFormatters: formatters,
      cursorHeight: 14,
      style: TextStyle(
        fontFamily: BTTypography.fontFamily,
        fontSize: 14.0,
        fontWeight: FontWeight.w500,
        height: 8 / 7,
        letterSpacing: 0,
        color: widget.disabled ? c.text.disabled : c.text.primary,
      ),
      decoration: InputDecoration(
        isCollapsed: true,
        border: InputBorder.none,
        // When floating: show hintText (optional placeholder).
        // When not floating: show label text as placeholder at 14px.
        hintText: _isValueFloating ? widget.hintText : widget.label,
        hintStyle: TextStyle(
          fontFamily: BTTypography.fontFamily,
          fontSize: 14.0,
          fontWeight: FontWeight.w500,
          height: 8 / 7,
          color: _isValueFloating ? c.text.tertiary : labelColor,
        ),
      ),
      onChanged: widget.onChanged,
    );

    // Tap anywhere in the container (padding, label area, empty space) to
    // focus — not just the TextField's own small hit target.
    // translucent so the clear × icon still receives its own tap events.
    return GestureDetector(
      behavior: HitTestBehavior.translucent,
      onTap: widget.disabled ? null : _focusNode.requestFocus,
      child: AnimatedContainer(
      duration: const Duration(milliseconds: 150),
      curve: const Cubic(0.4, 0, 0.2, 1),
      constraints: const BoxConstraints(minHeight: 48),
      padding: EdgeInsets.symmetric(
        horizontal: BTSpacing.sm,
        vertical: 8.0,
      ),
      decoration: BoxDecoration(
        color: widget.disabled ? c.bg.subtle : c.bg.primary,
        border: Border.all(color: border),
        borderRadius: BorderRadius.circular(BTRadius.sm),
      ),
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.center,
        children: [
          Expanded(
            child: SizedBox(
              height: 32.0,
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  labelWidget,
                  Expanded(
                    child: Align(
                      alignment: AlignmentDirectional.centerStart,
                      child: textField,
                    ),
                  ),
                ],
              ),
            ),
          ),
          // Clear × — mirrors base BTInput: visible when focused + has value.
          if (_isFocused && _hasValue && !widget.disabled) ...[
            SizedBox(width: 8.0),
            GestureDetector(
              onTap: _clearValue,
              child: Icon(
                Icons.cancel,
                size: 16,
                color: c.icon.primary,
              ),
            ),
          ],
        ],
      ),
    ),
    );
  }

  // ── Body ──────────────────────────────────────────────────────────────────

  Widget _buildBody(BuildContext context, {required String? errorText}) {
    final c = context.btColor;
    final hasError = errorText != null;
    // Shared TapRegion groupId — field row + dropdown overlay are one group.
    final tapGroupId = _overlayController;

    return OverlayPortal(
      controller: _overlayController,
      overlayChildBuilder: (_) => Positioned(
        top: _dropdownAbove ? null : _overlayTop,
        bottom: _dropdownAbove ? _overlayBottom : null,
        left: _overlayLeft,
        width: _overlayWidth,
        child: ConstrainedBox(
          constraints: BoxConstraints(
            maxHeight: _overlayMaxHeight.clamp(80, double.infinity),
          ),
          child: TapRegion(
          groupId: tapGroupId,
          onTapOutside: (_) => _closeDropdown(),
          child: atom.BTDropdownList<String>(
            variant: BTDropdownListVariant.list,
            items: widget.units
                .map(
                  (u) => BTDropdownItem<String>(
                    value: u.value,
                    label: u.label,
                    checked: u == _effectiveUnit,
                  ),
                )
                .toList(),
            onSelect: (String value) {
              final unit =
                  widget.units.firstWhere((u) => u.value == value);
              _selectUnit(unit);
            },
          ),
        ),
        ),
      ),
      child: TapRegion(
        groupId: tapGroupId,
        onTapOutside: (_) {
          _focusNode.unfocus();
          _closeDropdown();
        },
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                _buildUnitPanel(c, hasError: hasError),
                SizedBox(width: BTSpacing.xs),
                Expanded(
                  flex: 2,
                  child: _buildValueField(c, hasError: hasError),
                ),
              ],
            ),
            if (hasError) ...[
              SizedBox(height: 4.0),
              Text(
                errorText,
                style: TextStyle(
                  fontFamily: BTTypography.fontFamily,
                  fontSize: 12.0,
                  fontWeight: FontWeight.w500,
                  height: 4 / 3,
                  color: c.ext.error,
                ),
              ),
            ] else if (widget.helperText != null) ...[
              SizedBox(height: 4.0),
              Text(
                widget.helperText!,
                style: TextStyle(
                  fontFamily: BTTypography.fontFamily,
                  fontSize: 12.0,
                  fontWeight: FontWeight.w500,
                  height: 4 / 3,
                  color: c.text.secondary,
                ),
              ),
            ],
          ],
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    if (widget.validator != null) {
      return FormField<String>(
        autovalidateMode: AutovalidateMode.disabled,
        validator: (_) => widget.validator?.call(_textController.text),
        builder: (field) => _buildBody(
          context,
          errorText: widget.errorText ?? field.errorText,
        ),
      );
    }
    return _buildBody(context, errorText: widget.errorText);
  }
}

