import 'package:flutter/material.dart';

/// Input type — maps to keyboard + obscure behaviour.
enum BTInputType {
  text,
  password,
  email,
  number,
  tel,
  url,
}

/// Maps [BTInputType] to a [TextInputType] for the underlying TextField.
TextInputType keyboardTypeForBTInputType(BTInputType t) {
  switch (t) {
    case BTInputType.text:
    case BTInputType.password:
      return TextInputType.text;
    case BTInputType.email:
      return TextInputType.emailAddress;
    case BTInputType.number:
      return TextInputType.number;
    case BTInputType.tel:
      return TextInputType.phone;
    case BTInputType.url:
      return TextInputType.url;
  }
}

/// Whether a [BTInputType] obscures text by default.
bool obscuresByDefault(BTInputType t) => t == BTInputType.password;

/// Field height variant for date / time / dropdown input components.
///
/// - [normal]: 48 px minimum height, 14 px value text, 8 px vertical padding.
/// - [small]:  ~40 px auto height, 12 px value text, 12 px / 4 px vertical
///   padding (empty / floating).
enum BTInputSize { normal, small }

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/molecules/input/input.types.dart';
import 'package:flutter/material.dart';

/// Material-style inside-label text input — the foundation of the btech
/// input family. When [label] is set, the label sits inside the field border:
/// - **Empty + unfocused**: label shows as placeholder text (14 px, text.secondary)
/// - **Focused or filled**: label shrinks to 12 px at the top; value text appears below
///
/// When [label] is null, only [placeholder] hint text is shown (no animation).
///
/// Pass [validator] to integrate with Flutter's [Form] / [GlobalKey<FormState>]
/// system. [Form.validate()] will call the validator and show btech error styling
/// automatically — no manual [errorText] management needed.
///
/// ## Usage
/// ```dart
/// // Basic
/// BTInput(label: 'Username', onChanged: (v) => setState(() => name = v))
///
/// // Password with toggle
/// BTInput(label: 'Password', type: BTInputType.password, showPasswordToggle: true)
///
/// // Form validation (Flutter-native)
/// Form(
///   key: _formKey,
///   child: Column(children: [
///     BTInput(
///       label: 'Email',
///       validator: (v) => v!.isEmpty ? 'Email wajib diisi' : null,
///     ),
///     BTButton(label: 'Submit',
///       onPressed: () => _formKey.currentState!.validate()),
///   ]),
/// )
/// ```
class BTInput extends StatefulWidget {
  const BTInput({
    this.value,
    this.controller,
    this.focusNode,
    this.placeholder,
    this.label,
    this.required = false,
    this.disabled = false,
    this.readOnly = false,
    this.errorText,
    this.helperText,
    this.type = BTInputType.text,
    this.showPasswordToggle = false,
    this.multiline = false,
    this.minLines,
    this.maxLines,
    this.maxLength,
    this.showCharCount = false,
    this.prefix,
    this.suffix,
    this.clearable = false,
    this.leftLabel,
    this.rightLabel,
    this.leftLabelLeadingIcon,
    this.leftLabelTrailingIcon,
    this.rightLabelLeadingIcon,
    this.rightLabelTrailingIcon,
    this.onChanged,
    this.onFocus,
    this.onBlur,
    this.onSubmitted,
    this.onClear,
    this.onTap,
    this.validator,
    super.key,
  });

  final String? value;
  final TextEditingController? controller;
  final FocusNode? focusNode;
  final String? placeholder;
  final String? label;
  final bool required;
  final bool disabled;
  final bool readOnly;
  final String? errorText;
  final String? helperText;
  final BTInputType type;
  final bool showPasswordToggle;
  final bool multiline;
  final int? minLines;
  final int? maxLines;
  final int? maxLength;
  final bool showCharCount;
  final Widget? prefix;
  final Widget? suffix;
  final bool clearable;

  /// Text shown in the left label chip (InputWithLabel variant — Figma 368-6832).
  /// When set, a pill chip with [bg.subtle] background is attached to the left
  /// edge of the input border. Disabled state uses [bg.subtler].
  final String? leftLabel;

  /// Text shown in the right label chip. Works symmetrically with [leftLabel].
  final String? rightLabel;

  /// Optional leading 16×16 icon inside the left label chip.
  final Widget? leftLabelLeadingIcon;

  /// Optional trailing 16×16 icon inside the left label chip.
  final Widget? leftLabelTrailingIcon;

  /// Optional leading 16×16 icon inside the right label chip.
  final Widget? rightLabelLeadingIcon;

  /// Optional trailing 16×16 icon inside the right label chip.
  final Widget? rightLabelTrailingIcon;

  final ValueChanged<String>? onChanged;
  final VoidCallback? onFocus;
  final VoidCallback? onBlur;
  final ValueChanged<String>? onSubmitted;
  final VoidCallback? onClear;
  final VoidCallback? onTap;
  final FormFieldValidator<String>? validator;

  @override
  State<BTInput> createState() => _BTInputState();
}

class _BTInputState extends State<BTInput> {
  late TextEditingController _controller;
  late FocusNode _focusNode;
  bool _isFocused = false;
  bool _obscured = true;
  bool _ownsController = false;
  bool _ownsFocusNode = false;

  @override
  void initState() {
    super.initState();
    _controller =
        widget.controller ?? TextEditingController(text: widget.value);
    _ownsController = widget.controller == null;
    _focusNode = widget.focusNode ?? FocusNode();
    _ownsFocusNode = widget.focusNode == null;
    _focusNode.addListener(_handleFocusChange);
    _controller.addListener(_handleValueChange);
    _obscured = obscuresByDefault(widget.type);
  }

  @override
  void didUpdateWidget(BTInput old) {
    super.didUpdateWidget(old);
    final newValue = widget.value;
    if (newValue != null && newValue != _controller.text) {
      _controller.value = _controller.value.copyWith(
        text: newValue,
        selection: _controller.selection.baseOffset <= newValue.length
            ? _controller.selection
            : TextSelection.collapsed(offset: newValue.length),
      );
    }
  }

  @override
  void dispose() {
    _focusNode.removeListener(_handleFocusChange);
    _controller.removeListener(_handleValueChange);
    if (_ownsController) _controller.dispose();
    if (_ownsFocusNode) _focusNode.dispose();
    super.dispose();
  }

  void _handleFocusChange() {
    setState(() => _isFocused = _focusNode.hasFocus);
    if (_focusNode.hasFocus) {
      widget.onFocus?.call();
    } else {
      widget.onBlur?.call();
    }
  }

  void _handleValueChange() {
    setState(() {}); // rebuild for label/suffix state
  }

  bool get _isEmpty => _controller.text.isEmpty;

  /// True when the label should appear small at the top (focused or has a value).
  bool get _isFloating => _isFocused || !_isEmpty;

  void _onClear() {
    _controller.clear();
    widget.onChanged?.call('');
    widget.onClear?.call();
  }

  // ── Color helpers ─────────────────────────────────────────────────────────────

  Color _borderColor(BTColorTheme c, {required bool hasError}) {
    if (widget.disabled) return c.border.primary;
    // Figma: error border = ext.error (#ef4444)
    if (hasError) return c.ext.error;
    if (_isFocused) return c.brand.primary;
    return c.border.primary;
  }

  /// Label color: ext.error for error, text.secondary otherwise.
  /// Focused (non-error) label stays text.secondary — NOT brand.primary.
  Color _labelColor(BTColorTheme c, {required bool hasError}) {
    if (widget.disabled) return c.text.disabled;
    if (hasError) return c.ext.error;
    return c.text.secondary;
  }

  Color _valueColor(BTColorTheme c) {
    return widget.disabled ? c.text.disabled : c.text.primary;
  }

  // ── Suffix resolution ─────────────────────────────────────────────────────────
  // Priority:
  //   1. error icon        — always when hasError
  //   2. active cancel ×   — focused + has content (Figma active state, node 699-2749)
  //   3. password toggle   — when not focused or field is empty
  //   4. clearable ×       — clearable prop, when not focused
  //   5. user suffix

  Widget? _resolveSuffix({required bool hasError}) {
    final c = context.btColor;
    if (hasError) {
      return Icon(Icons.error_outline_rounded, size: 16, color: c.ext.error);
    }
    // Active state: show cancel whenever focused + has content.
    if (_isFocused && !_isEmpty && !widget.disabled && !widget.readOnly) {
      return GestureDetector(
        onTap: _onClear,
        child: Icon(Icons.cancel, size: 16, color: c.icon.primary),
      );
    }
    if (widget.type == BTInputType.password && widget.showPasswordToggle) {
      return GestureDetector(
        onTap: () => setState(() => _obscured = !_obscured),
        child: Icon(
          _obscured
              ? Icons.visibility_outlined
              : Icons.visibility_off_outlined,
          size: 16,
          color:  c.icon.primary,
        ),
      );
    }
    if (widget.clearable && !_isEmpty && !widget.disabled && !widget.readOnly) {
      return GestureDetector(
        onTap: _onClear,
        child: Icon(Icons.cancel, size: 16, color:  c.icon.primary),
      );
    }
    return widget.suffix;
  }

  // ── Label chip (InputWithLabel variant — Figma 368-6832) ──────────────────────

  /// Renders a label chip attached to the left or right edge of the input.
  ///
  /// The chip fills the full row height via [CrossAxisAlignment.stretch] on its
  /// parent [Row]. A [SizedBox(height: 48)] wraps the Row for single-line inputs
  /// so that stretch has a finite cross-axis constraint — [IntrinsicHeight] is
  /// intentionally NOT used because [TextField] does not report a finite
  /// intrinsic height and would cause the row to expand unboundedly.
  ///
  /// [ClipRRect] clips chip backgrounds to the inner radius (BTRadius.sm − 1
  /// = 7px, accounting for the 1px outer border).
  ///
  /// The chip→field divider is a 1px [BorderSide] that animates in sync with
  /// the outer border via [AnimatedContainer].
  Widget _buildLabelChip(
    BTColorTheme c, {
    required String text,
    required bool isLeft,
    required bool hasError,
    Widget? leadingIcon,
    Widget? trailingIcon,
  }) {
    // Disabled: bg.subtler (neutral-200, darker than bg.subtle neutral-50).
    final bgColor = widget.disabled ? c.bg.subtler : c.bg.subtle;
    final textColor = widget.disabled ? c.text.disabled : c.text.primary;
    // Divider matches the animated outer border color (focus = brand.primary,
    // error = ext.error, default = border.primary).
    final dividerColor = _borderColor(c, hasError: hasError);

    return AnimatedContainer(
      duration: const Duration(milliseconds: 150),
      curve: const Cubic(0.4, 0, 0.2, 1),
      padding: EdgeInsets.symmetric(horizontal: 8.0),
      decoration: BoxDecoration(
        color: bgColor,
        border: BorderDirectional(
          end: isLeft
              ? BorderSide(color: dividerColor)
              : BorderSide.none,
          start: isLeft
              ? BorderSide.none
              : BorderSide(color: dividerColor),
        ),
      ),
      child: Row(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.center,
        children: [
          if (leadingIcon != null) ...[
            IconTheme(
              data: IconThemeData(size: 16, color: textColor),
              child: leadingIcon,
            ),
            SizedBox(width: 4.0),
          ],
          Text(
            text,
            style: TextStyle(
              fontFamily: BTTypography.fontFamily,
              fontSize: 12.0,
              fontWeight: FontWeight.w500,
              height: 4 / 3,
              color: textColor,
            ),
          ),
          if (trailingIcon != null) ...[
            SizedBox(width: 4.0),
            IconTheme(
              data: IconThemeData(size: 16, color: textColor),
              child: trailingIcon,
            ),
          ],
        ],
      ),
    );
  }

  // ── Content area ──────────────────────────────────────────────────────────────

  /// Label text (no asterisk — asterisk is rendered separately in red).
  String get _labelText => widget.label!;

  Widget _buildContent(BTColorTheme c, {required bool hasError}) {
    final hasLabel = widget.label != null;

    if (!hasLabel) {
      return _buildTextField(c, hintText: widget.placeholder);
    }

    // Build shared sub-widgets once and reuse in both branches below.
    final labelWidget = ClipRect(
      child: AnimatedAlign(
        duration: const Duration(milliseconds: 150),
        curve: const Cubic(0.4, 0, 0.2, 1),
        alignment: AlignmentDirectional.topStart,
        heightFactor: _isFloating ? 1.0 : 0.0,
        child: Text.rich(
          TextSpan(
            children: [
              TextSpan(text: _labelText),
              if (widget.required)
                TextSpan(
                  text: ' *',
                  style: TextStyle(color: c.ext.error),
                ),
            ],
          ),
          maxLines: 1,
          overflow: TextOverflow.ellipsis,
          style: TextStyle(
            fontFamily: BTTypography.fontFamily,
            fontSize: 12.0,
            fontWeight: FontWeight.w500,
            height: 4 / 3, // lineHeight 16px / fontSize 12px
            color: _labelColor(c, hasError: hasError),
          ),
        ),
      ),
    );

    final textFieldWidget = _buildTextField(
      c,
      hintText: _isFloating ? widget.placeholder : widget.label,
      hintColor: _isFloating
          ? c.text.tertiary
          : _labelColor(c, hasError: hasError),
    );

    // Multiline: Column grows with content — no fixed height constraint.
    if (widget.multiline) {
      return Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        mainAxisSize: MainAxisSize.min,
        children: [labelWidget, textFieldWidget],
      );
    }

    // Single-line: SizedBox(height:32) pins content to exactly 32 px so the
    // outer AnimatedContainer(minHeight:48) + vertPad(8+8) always totals
    // exactly 48 px — regardless of font-metric differences between platforms.
    //
    // Expanded absorbs the space freed as the label animates in/out:
    //   not-floating → Expanded=32 px (label=0),  text centered in 32 px
    //   floating     → Expanded=16 px (label=16 px), text centered in 16 px
    //
    // This matches the pattern used by BTInputDropdown._buildContent.
    return SizedBox(
      height: 32.0,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          labelWidget,
          Expanded(
            child: Align(
              alignment: AlignmentDirectional.centerStart,
              child: textFieldWidget,
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildTextField(
    BTColorTheme c, {
    String? hintText,
    Color? hintColor,
    double hintFontSize = 14.0,
  }) {
    // readOnly blocks ALL pointer events — no focus, no cursor, no blue border.
    // Visually identical to disabled except the text/border colors stay normal.
    return IgnorePointer(
      ignoring: widget.readOnly,
      child: TextField(
      controller: _controller,
      focusNode: _focusNode,
      enabled: !widget.disabled,
      readOnly: widget.readOnly,
      obscureText: widget.type == BTInputType.password && _obscured,
      cursorHeight: 14, // matches value text fontSize
      keyboardType: widget.multiline
          ? TextInputType.multiline
          : keyboardTypeForBTInputType(widget.type),
      maxLines: widget.multiline ? widget.maxLines : 1,
      minLines: widget.multiline ? (widget.minLines ?? 5) : 1,
      maxLength: widget.maxLength,
      onChanged: widget.onChanged,
      onSubmitted: widget.onSubmitted,
      onTap: widget.onTap,
      style: TextStyle(
        fontFamily: BTTypography.fontFamily,
        fontSize: 14.0,
        fontWeight: FontWeight.w500,
        height: 8 / 7, // lineHeight 16px / fontSize 14px
        color: _valueColor(c),
      ),
      decoration: InputDecoration(
        isCollapsed: true,
        border: InputBorder.none,
        hintText: hintText,
        hintStyle: TextStyle(
          fontFamily: BTTypography.fontFamily,
          fontSize: hintFontSize,
          fontWeight: FontWeight.w500,
          height: 16 / hintFontSize, // lineHeight 16px
          color: hintColor ?? c.text.tertiary,
        ),
        counterText: '',
      ),
    ));
  }

  // ── Build ─────────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    // When validator is provided, wrap in FormField so Form.validate() works.
    // FormField.builder is called with the current FormFieldState, which carries
    // the validation error after Form.validate() runs — enabling btech error
    // styling (red border + error icon + error text) without manual errorText.
    if (widget.validator != null) {
      return TapRegion(
        onTapOutside: (_) => _focusNode.unfocus(),
        child: FormField<String>(
          autovalidateMode: AutovalidateMode.disabled,
          validator: (_) => widget.validator!(_controller.text),
          builder: (field) => _buildBody(
            context,
            errorText: widget.errorText ?? field.errorText,
          ),
        ),
      );
    }
    return TapRegion(
      onTapOutside: (_) => _focusNode.unfocus(),
      child: _buildBody(context, errorText: widget.errorText),
    );
  }

  Widget _buildBody(BuildContext context, {required String? errorText}) {
    final c = context.btColor;
    final hasError = errorText != null;
    final suffix = _resolveSuffix(hasError: hasError);

    // p-8 when label is present (label animation uses the freed space),
    // p-16 when no label (centers the text in the 48px container).
    // Using a constant based only on label presence — NOT _isFloating — prevents
    // the snap/animation desync that causes Column overflow when un-focusing:
    // if vertPad snapped 8→16 while heightFactor was still near 1, the column
    // (~32px) would exceed the newly available 16px space.
    final vertPad = widget.label != null ? 8.0 : 16.0;

    final hasLeftLabel = widget.leftLabel != null;
    final hasRightLabel = widget.rightLabel != null;
    final hasAnyLabel = hasLeftLabel || hasRightLabel;

    // Shared decoration — same for both layouts.
    final decoration = BoxDecoration(
      color: widget.disabled ? c.bg.subtle : c.bg.primary,
      border:
          Border.all(color: _borderColor(c, hasError: hasError), width: 1.0),
      borderRadius: BorderRadius.circular(BTRadius.sm), // radius.sm = 8px
    );

    final Widget field;

    if (hasAnyLabel) {
      // InputWithLabel layout — chips fill the full row height.
      //
      // SizedBox(height: 48) gives the Row a finite cross-axis constraint so
      // CrossAxisAlignment.stretch works correctly. IntrinsicHeight is NOT used
      // because TextField does not support intrinsic height measurement and
      // returns an unbounded value, causing the row to expand far beyond 48px.
      //
      // For multiline inputs: height is null (unconstrained) and chips use
      // CrossAxisAlignment.center instead of stretch.
      //
      // ClipRRect clips chip backgrounds to the inner radius (BTRadius.sm − 1
      // = 7px, accounting for the 1px outer border) so corners render cleanly.
      field = AnimatedContainer(
        duration: const Duration(milliseconds: 150),
        curve: const Cubic(0.4, 0, 0.2, 1),
        constraints: BoxConstraints(minHeight: widget.multiline ? 0 : 48.0),
        decoration: decoration,
        child: ClipRRect(
          borderRadius: BorderRadius.circular(BTRadius.sm - 1),
          child: SizedBox(
            height: widget.multiline ? null : 48.0,
            child: Row(
              crossAxisAlignment: widget.multiline
                  ? CrossAxisAlignment.center
                  : CrossAxisAlignment.stretch,
              children: [
                if (hasLeftLabel)
                  _buildLabelChip(
                    c,
                    text: widget.leftLabel!,
                    leadingIcon: widget.leftLabelLeadingIcon,
                    trailingIcon: widget.leftLabelTrailingIcon,
                    isLeft: true,
                    hasError: hasError,
                  ),
                Expanded(
                  child: Padding(
                    padding: EdgeInsets.symmetric(
                      horizontal: 8.0,
                      vertical: widget.multiline ? 12.0 : vertPad,
                    ),
                    child: Row(
                      crossAxisAlignment: CrossAxisAlignment.center,
                      children: [
                        if (widget.prefix != null) ...[
                          widget.prefix!,
                          SizedBox(width: 8.0),
                        ],
                        Expanded(child: _buildContent(c, hasError: hasError)),
                        ClipRect(
                          child: AnimatedAlign(
                            duration: const Duration(milliseconds: 150),
                            curve: const Cubic(0.4, 0, 0.2, 1),
                            alignment: AlignmentDirectional.centerEnd,
                            widthFactor: suffix == null ? 0.0 : 1.0,
                            child: Row(
                              mainAxisSize: MainAxisSize.min,
                              children: [
                                SizedBox(width: 8.0),
                                AnimatedSwitcher(
                                  duration: const Duration(milliseconds: 100),
                                  child: SizedBox(
                                    key: ValueKey(suffix?.runtimeType),
                                    child: suffix ?? const SizedBox.shrink(),
                                  ),
                                ),
                              ],
                            ),
                          ),
                        ),
                      ],
                    ),
                  ),
                ),
                if (hasRightLabel)
                  _buildLabelChip(
                    c,
                    text: widget.rightLabel!,
                    leadingIcon: widget.rightLabelLeadingIcon,
                    trailingIcon: widget.rightLabelTrailingIcon,
                    isLeft: false,
                    hasError: hasError,
                  ),
              ],
            ),
          ),
        ),
      );
    } else {
      // Default layout — no label chips.
      // NO boxShadow — Figma active state has no halo/glow, only border-color change.
      field = AnimatedContainer(
        duration: const Duration(milliseconds: 150),
        curve: const Cubic(0.4, 0, 0.2, 1),
        constraints: BoxConstraints(minHeight: widget.multiline ? 0 : 48.0),
        padding: EdgeInsets.symmetric(
          horizontal: 8.0, // spacing.sm
          vertical: widget.multiline ? 12.0 : vertPad,
        ),
        decoration: decoration,
        child: Row(
          crossAxisAlignment: CrossAxisAlignment.center,
          children: [
            if (widget.prefix != null) ...[
              widget.prefix!, // caller should size to 16×16
              SizedBox(width: 8.0),
            ],
            Expanded(child: _buildContent(c, hasError: hasError)),
            if (suffix != null) ...[
              SizedBox(width: 8.0),
              suffix,
            ],
          ],
        ),
      );
    }

    final hasBelow =
        hasError || widget.helperText != null || widget.showCharCount;

    // Tap anywhere in the field box (padding, label area, empty space) to
    // focus — not just the TextField's own hit target. translucent so suffix
    // icons and other interactive children still receive their own events.
    final tappableField = GestureDetector(
      behavior: HitTestBehavior.translucent,
      onTap: (widget.disabled || widget.readOnly) ? null : _focusNode.requestFocus,
      child: field,
    );

    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        tappableField,
        if (hasBelow)
          Padding(
            // spacing.xs = 4px gap between field and validation text
            padding: EdgeInsets.only(top: 4.0),
            child: Row(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Expanded(
                  child: Text(
                    errorText ?? widget.helperText ?? '',
                    style: TextStyle(
                      fontFamily: BTTypography.fontFamily,
                      fontSize: 12.0,
                      fontWeight: FontWeight.w500,
                      height: 4 / 3, // lineHeight 16px / 12px
                      color: hasError ? c.ext.error : c.text.secondary,
                    ),
                  ),
                ),
                if (widget.showCharCount && widget.maxLength != null)
                  Text(
                    '${_controller.text.length}/${widget.maxLength}',
                    style: TextStyle(
                      fontFamily: BTTypography.fontFamily,
                      fontSize: 12.0,
                      fontWeight: FontWeight.w500,
                      height: 4 / 3,
                      color: hasError ? c.ext.error : c.text.secondary,
                    ),
                  ),
              ],
            ),
          ),
      ],
    );
  }
}

/// Shared item model for [BTInputSingleOptions] and [BTInputMultipleOptions].
class BTInputOptionsItem<T> {
  const BTInputOptionsItem({
    required this.value,
    required this.label,
  });

  /// The value emitted when this option is selected.
  final T value;

  /// Label text displayed next to the control.
  final String label;
}

/// Backward-compatible alias — prefer [BTInputOptionsItem].
typedef BTInputSingleOptionsItem<T> = BTInputOptionsItem<T>;

/// BTInputMultipleField — multi-value tag input with overlay dropdown.
/// Figma M node 555-4109.
///
/// The field body contains an inline text cursor so the user can type
/// directly and press Enter to add a free-text [BTTag]. Tapping the
/// chevron suffix opens a checkbox [BTDropdownList] to pick predefined
/// [items]; checking / unchecking toggles their tags.
///
/// Two tag layout [type]s are supported:
/// - [BTInputMultipleFieldType.wrap] — tags wrap across multiple rows;
///   field height grows with content.
/// - [BTInputMultipleFieldType.scroll] — single fixed-height row; tags
///   scroll horizontally; the cursor is always at the trailing end.
///
/// ## Usage
/// ```dart
/// // Wrap type (default) — with predefined dropdown items
/// BTInputMultipleField<String>(
///   label: 'Frameworks',
///   required: true,
///   items: const [
///     BTDropdownItem(value: 'flutter', label: 'Flutter'),
///     BTDropdownItem(value: 'react',   label: 'React'),
///   ],
///   onChanged: (tags) => setState(() => _tags = tags),
/// )
///
/// // Scroll type — fixed single-row height
/// BTInputMultipleField<String>(
///   label: 'Skills',
///   type: BTInputMultipleFieldType.scroll,
///   items: _skillItems,
///   hasSearch: true,
///   onChanged: (tags) => setState(() => _skills = tags),
/// )
///
/// // Form validation
/// BTInputMultipleField<String>(
///   label: 'Role',
///   required: true,
///   items: _roleItems,
///   onChanged: (tags) => setState(() => _roles = tags),
///   validator: (v) =>
///       (v == null || v.isEmpty) ? 'Pilih setidaknya satu' : null,
/// )
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import '../../dropdown-list/dropdown_list.types.dart';
import '../../dropdown-list/dropdown_list.widget.dart';
import '../../tag/tag.types.dart';
import '../../tag/tag.widget.dart';
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

/// Controls how tags are laid out inside [BTInputMultipleField].
enum BTInputMultipleFieldType {
  /// Tags wrap onto multiple rows. Field height grows with content.
  wrap,

  /// Tags appear on a single horizontally-scrollable row. Field height
  /// is fixed; the text cursor is always at the trailing end.
  scroll,
}

class BTInputMultipleField<T> extends StatefulWidget {
  const BTInputMultipleField({
    this.items = const [],
    this.label,
    this.type = BTInputMultipleFieldType.wrap,
    this.required = false,
    this.disabled = false,
    this.errorText,
    this.helperText,
    this.leftIcon,
    this.hasSearch = false,
    this.itemsFilter,
    this.emptyLabel = 'No result found.',
    this.onChanged,
    this.validator,
    super.key,
  });

  /// Predefined selectable options shown in the dropdown with checkboxes.
  final List<BTDropdownItem<T>> items;

  /// Label that floats small (12 px) when the field has content or focus,
  /// and renders as the inline hint (14 px) when empty and idle.
  final String? label;

  /// Controls the tag layout — [BTInputMultipleFieldType.wrap] (default)
  /// or [BTInputMultipleFieldType.scroll].
  final BTInputMultipleFieldType type;

  /// Appends " *" (red) to [label] when `true`.
  final bool required;

  /// Disables all interaction and applies disabled visual state.
  final bool disabled;

  /// When set, renders a red border and validation text below the field.
  final String? errorText;

  /// Helper text shown below the field when there is no error.
  final String? helperText;

  /// Optional 16×16 widget prepended to the left (slot).
  final Widget? leftIcon;

  /// Show a search input at the top of the dropdown list.
  final bool hasSearch;

  /// Custom filter applied when [hasSearch] is true and the user types a query.
  /// Receives the full [items] list and the current query string; returns the
  /// filtered subset to display.
  ///
  /// When null, defaults to a case-insensitive [String.contains] match on
  /// [BTDropdownItem.label].
  ///
  /// ```dart
  /// itemsFilter: (items, query) => items
  ///     .where((i) =>
  ///         i.label.toLowerCase().contains(query) ||
  ///         i.value.toString().toLowerCase().startsWith(query))
  ///     .toList(),
  /// ```
  final List<BTDropdownItem<T>> Function(
    List<BTDropdownItem<T>> items,
    String query,
  )? itemsFilter;

  /// Text shown beneath the empty-state illustration in the dropdown.
  final String emptyLabel;

  /// Called with the current list of [BTTagItem] on every change
  /// (item toggled, tag typed, tag removed, clear-all).
  final ValueChanged<List<BTTagItem>>? onChanged;

  /// Validator for [Form.validate] integration.
  final FormFieldValidator<List<BTTagItem>>? validator;

  @override
  State<BTInputMultipleField<T>> createState() =>
      _BTInputMultipleFieldState<T>();
}

class _BTInputMultipleFieldState<T> extends State<BTInputMultipleField<T>> {
  final _overlayController = OverlayPortalController();
  final _scrollController = ScrollController();

  late final TextEditingController _textController;
  late final FocusNode _focusNode;

  // Single insertion-ordered tag list. Both dropdown selections and typed
  // tags are appended here so each new item always appears AFTER the last
  // existing one, regardless of how it was added.
  final List<BTTagItem> _tags = [];

  String _searchQuery = '';
  bool _isOpen = false;

  // Object used as a TapRegion groupId so the field and the dropdown
  // share the same tap group (tapping inside either does NOT close the
  // dropdown; tapping outside either DOES close it).
  final _tapGroupId = Object();

  // GlobalKey on the AnimatedContainer so we can read its rendered bounds
  // via RenderBox.localToGlobal / .size for precise overlay positioning.
  final _fieldKey = GlobalKey();

  // Screen-space position for the Positioned dropdown overlay.
  // Kept in sync via _syncDropdownPosition / _refreshDropdownPosition.
  //
  // When _dropdownAbove is false: Positioned uses top: _overlayTop (below).
  // When _dropdownAbove is true:  Positioned uses bottom: _overlayBottom
  //   (= screen height − field top + gap) so the dropdown flips above the
  //   field when there is not enough vertical space below it.
  static const _kMinSpaceBelow = 180.0;
  bool _dropdownAbove = false;
  double _overlayTop = 0;
  double _overlayBottom = 0;
  double _overlayLeft = 0;
  double _overlayWidth = 210;
  double _overlayMaxHeight = 300;

  /// Width of the inline text cursor in wrap mode.
  /// Starts at 60 px (minimum) and grows with the typed text so the cursor
  /// sits on the SAME row as the last tag instead of expanding to fill the
  /// full Wrap row and always wrapping. Reset to 60 when a tag is committed.
  double _inlineWidth = 60;

  // ── Lifecycle ──────────────────────────────────────────────────────────────

  @override
  void initState() {
    super.initState();
    _textController = TextEditingController();
    _focusNode = FocusNode()
      ..addListener(_onFocusChange)
      ..onKeyEvent = _handleKeyEvent;
  }

  // Backspace on empty field removes the last tag one by one.
  KeyEventResult _handleKeyEvent(FocusNode node, KeyEvent event) {
    if (event is KeyDownEvent &&
        event.logicalKey == LogicalKeyboardKey.backspace &&
        _textController.text.isEmpty &&
        _tags.isNotEmpty) {
      _removeTag(_tags.last);
      return KeyEventResult.handled;
    }
    return KeyEventResult.ignored;
  }

  @override
  void dispose() {
    _textController.dispose();
    _focusNode
      ..removeListener(_onFocusChange)
      ..dispose();
    _scrollController.dispose();
    super.dispose();
  }

  void _onFocusChange() => setState(() {});

  // ── Derived state ──────────────────────────────────────────────────────────

  bool get _isFocused => _focusNode.hasFocus;

  bool get _isFloating =>
      _currentTags.isNotEmpty ||
      _isFocused ||
      _textController.text.isNotEmpty ||
      _isOpen;

  /// All current tags in insertion order.
  List<BTTagItem> get _currentTags => _tags;

  List<BTDropdownItem<T>> get _filteredItems {
    final List<BTDropdownItem<T>> source;
    if (_searchQuery.isEmpty || !widget.hasSearch) {
      source = widget.items;
    } else if (widget.itemsFilter != null) {
      source = widget.itemsFilter!(widget.items, _searchQuery);
    } else {
      final q = _searchQuery.toLowerCase();
      source =
          widget.items.where((i) => i.label.toLowerCase().contains(q)).toList();
    }
    return source
        .map(
          (i) => BTDropdownItem<T>(
            value: i.value,
            label: i.label,
            disabled: i.disabled,
            avatar: i.avatar,
            // checked when the item's value id is already in _tags
            checked: i.value != null &&
                _tags.any((t) => t.id == i.value.toString()),
          ),
        )
        .toList();
  }

  // ── Scroll helpers ─────────────────────────────────────────────────────────

  /// After any tag change in scroll mode, jump to the trailing end so the
  /// cursor is always visible.
  void _scrollToEnd() {
    if (widget.type != BTInputMultipleFieldType.scroll) return;
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (_scrollController.hasClients) {
        _scrollController.animateTo(
          _scrollController.position.maxScrollExtent,
          duration: const Duration(milliseconds: 150),
          curve: Curves.easeOut,
        );
      }
    });
  }

  /// Recomputes [_inlineWidth] from the current typed text.
  /// Must be called inside [setState] — does NOT call setState itself.
  /// After measuring, also scrolls the horizontal scroll view to the end
  /// so the cursor stays visible in scroll-type layouts.
  void _updateInlineWidth() {
    final text = _textController.text;
    if (text.isEmpty) {
      _inlineWidth = 60;
      _scrollToEnd();
      return;
    }
    final painter = TextPainter(
      text: TextSpan(
        text: text,
        style: TextStyle(
          fontFamily: BTTypography.fontFamily,
          fontSize: 14.0,
          fontWeight: FontWeight.w500,
        ),
      ),
      textDirection: TextDirection.ltr,
    )..layout();
    // +8 px for cursor; clamp to 60 px minimum.
    _inlineWidth = (painter.width + 8).clamp(60.0, double.infinity);
    _scrollToEnd();
  }

  // ── Dropdown overlay positioning ───────────────────────────────────────────

  /// Reads the field's current rendered position + size synchronously.
  /// Safe to call from gesture callbacks (layout has already run by then).
  /// Writes directly to the three overlay fields — does NOT call setState.
  void _syncDropdownPosition() {
    final box = _fieldKey.currentContext?.findRenderObject() as RenderBox?;
    if (box == null || !box.attached) return;
    final origin = box.localToGlobal(Offset.zero);
    final size = box.size;
    final screenHeight = MediaQuery.sizeOf(context).height;
    final fieldBottom = origin.dy + size.height;
    final spaceBelow = screenHeight - fieldBottom;
    final spaceAbove = origin.dy;

    _dropdownAbove = spaceBelow < _kMinSpaceBelow;
    _overlayLeft = origin.dx;
    _overlayWidth = size.width;
    if (_dropdownAbove) {
      // bottom: distance from screen bottom to the field's top edge + gap.
      _overlayBottom = screenHeight - origin.dy + 4;
      _overlayMaxHeight = spaceAbove - 8;
    } else {
      _overlayTop = fieldBottom + 4;
      _overlayMaxHeight = spaceBelow - 8;
    }
  }

  /// Schedules a position refresh AFTER the current frame's layout.
  /// Use this whenever a setState may change the field height (tag added /
  /// removed). The one-frame lag (~16 ms) is imperceptible at 60 fps.
  void _refreshDropdownPosition() {
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted || !_isOpen) return;
      final box = _fieldKey.currentContext?.findRenderObject() as RenderBox?;
      if (box == null || !box.attached) return;
      final origin = box.localToGlobal(Offset.zero);
      final size = box.size;
      final screenHeight = MediaQuery.sizeOf(context).height;
      final fieldBottom = origin.dy + size.height;
      final spaceBelow = screenHeight - fieldBottom;
      final spaceAbove = origin.dy;
      final above = spaceBelow < _kMinSpaceBelow;
      final top = fieldBottom + 4;
      final bottom = screenHeight - origin.dy + 4;
      final left = origin.dx;
      final width = size.width;
      final maxH = above ? spaceAbove - 8 : spaceBelow - 8;
      // Only rebuild when coords actually changed to avoid infinite loops.
      final changed = _dropdownAbove != above ||
          _overlayTop != top ||
          _overlayBottom != bottom ||
          _overlayLeft != left ||
          _overlayWidth != width ||
          _overlayMaxHeight != maxH;
      if (changed) {
        setState(() {
          _dropdownAbove = above;
          _overlayTop = top;
          _overlayBottom = bottom;
          _overlayLeft = left;
          _overlayWidth = width;
          _overlayMaxHeight = maxH;
        });
      }
    });
  }

  // ── Open / close dropdown ──────────────────────────────────────────────────

  void _open() {
    if (_isOpen || widget.disabled) return;
    // Read position synchronously — layout has already completed by the time
    // the user's tap gesture fires, so the bounds are current.
    _syncDropdownPosition();
    setState(() {
      _isOpen = true;
      _searchQuery = '';
    });
    _overlayController.show();
  }

  void _close() {
    if (!_isOpen) return;
    _overlayController.hide();
    setState(() => _isOpen = false);
  }

  void _toggle() => _isOpen ? _close() : _open();

  // ── Tag management ─────────────────────────────────────────────────────────

  void _handleDropdownToggle(T value) {
    final id = value.toString();
    final existingIndex = _tags.indexWhere((t) => t.id == id);
    if (existingIndex >= 0) {
      // Already selected → remove it (uncheck).
      setState(() => _tags.removeAt(existingIndex));
    } else {
      // Not selected → append at the end (insertion order preserved).
      final match = widget.items.where((i) => i.value == value);
      final label = match.isEmpty ? id : match.first.label;
      setState(() => _tags.add(BTTagItem(id: id, label: label)));
    }
    widget.onChanged?.call(_currentTags);
    _scrollToEnd();
    // Field may have grown (new tag row) — reposition dropdown below the
    // updated field height after layout completes.
    _refreshDropdownPosition();
  }

  /// Called when the user presses Enter in the inline text field.
  void _handleTypedTag(String text) {
    _textController.clear();
    final trimmed = text.trim();
    if (trimmed.isNotEmpty) {
      final alreadyPresent = _currentTags
          .any((t) => t.label.toLowerCase() == trimmed.toLowerCase());
      if (!alreadyPresent) {
        setState(() {
          _inlineWidth = 60; // reset after tag committed
          _tags.add(BTTagItem(id: 'custom_$trimmed', label: trimmed));
        });
        widget.onChanged?.call(_currentTags);
        _scrollToEnd();
      } else {
        // Duplicate — still reset width since text was cleared.
        setState(() { _inlineWidth = 60; });
      }
    } else {
      setState(() { _inlineWidth = 60; });
    }
    // Keep focus so the user can immediately type the next tag.
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted) _focusNode.requestFocus();
    });
  }

  /// Remove a single tag by its effectiveId.
  void _removeTag(BTTagItem tag) {
    setState(() => _tags.removeWhere((t) => t.effectiveId == tag.effectiveId));
    widget.onChanged?.call(_currentTags);
    _scrollToEnd();
    _refreshDropdownPosition();
  }

  void _clearAll() {
    setState(() {
      _tags.clear();
      _textController.clear();
      _inlineWidth = 60;
    });
    _close();
    widget.onChanged?.call([]);
  }

  // ── Color helpers ──────────────────────────────────────────────────────────

  Color _borderColor(BTColorTheme c, {required bool hasError}) {
    if (widget.disabled) return c.border.primary;
    if (hasError) return c.ext.error;
    if (_isOpen || _isFocused) return c.brand.primary;
    return c.border.primary;
  }

  Color _labelColor(BTColorTheme c, {required bool hasError}) {
    if (widget.disabled) return c.text.disabled;
    if (hasError) return c.ext.error;
    return c.text.secondary;
  }

  // ── Tag layout builders ────────────────────────────────────────────────────

  /// Inline text field — shared between both layout types.
  ///
  /// **Width strategy (wrap mode):**
  /// - Has tags OR typed text → [_inlineWidth] (TextPainter-measured, min
  ///   60 px). This keeps the cursor on the SAME row as the last tag by
  ///   giving [Wrap] an explicit small width instead of the full-row max.
  /// - Empty + no tags → `null` (unconstrained). The hint label text
  ///   spans the full field width so the empty state looks correct.
  ///
  /// **Width strategy (scroll mode):** fixed [fixedWidth] from caller.
  Widget _buildInlineTextField(
    BTColorTheme c, {
    required Color labelColor,
    required bool isFloating,
    double? fixedWidth,
  }) {
    final hasTags = _currentTags.isNotEmpty;
    final hasText = _textController.text.isNotEmpty;
    final effectiveWidth =
        fixedWidth ?? (hasTags || hasText ? _inlineWidth : null);
    return SizedBox(
      height: 20.0,
      width: effectiveWidth,
      child: _textField(c, labelColor: labelColor, isFloating: isFloating),
    );
  }

  Widget _textField(
    BTColorTheme c, {
    required Color labelColor,
    required bool isFloating,
  }) {
    return TextField(
      controller: _textController,
      focusNode: _focusNode,
      enabled: !widget.disabled,
      cursorHeight: 12,
      onSubmitted: _handleTypedTag,
      onChanged: (_) => setState(_updateInlineWidth),
      textInputAction: TextInputAction.done,
      style: TextStyle(
        fontFamily: BTTypography.fontFamily,
        fontSize: 14.0,
        fontWeight: FontWeight.w500,
        color: widget.disabled ? c.text.disabled : c.text.primary,
      ),
      decoration: InputDecoration.collapsed(
        hintText:
            (!isFloating && widget.label != null) ? widget.label : null,
        hintStyle: TextStyle(
          fontFamily: BTTypography.fontFamily,
          fontSize: 14.0,
          fontWeight: FontWeight.w500,
          height: 16 / 14,
          color: labelColor,
        ),
      ),
    );
  }

  /// Wrap layout — tags wrap onto multiple rows; height follows content.
  Widget _buildWrapContent(
    List<BTTagItem> tags,
    BTColorTheme c, {
    required Color labelColor,
    required bool isFloating,
  }) {
    final isActive = _isFocused || _isOpen;
    return Wrap(
      spacing: BTSpacing.xs,
      runSpacing: BTSpacing.xs,
      children: [
        ...List.generate(tags.length, (i) {
          final tag = tags[i];
          return BTTag(
            key: ValueKey(tag.effectiveId),
            label: tag.label,
            onRemove: (!widget.disabled && isActive)
                ? () => _removeTag(tag)
                : null,
          );
        }),
        _buildInlineTextField(
          c,
          labelColor: labelColor,
          isFloating: isFloating,
        ),
      ],
    );
  }

  /// Scroll layout — single fixed-height horizontal row; cursor always
  /// sits at the trailing end after the last tag.
  Widget _buildScrollContent(
    List<BTTagItem> tags,
    BTColorTheme c, {
    required Color labelColor,
    required bool isFloating,
  }) {
    final hasTags = tags.isNotEmpty;
    final hasText = _textController.text.isNotEmpty;
    final isActive = _isFocused || _isOpen;
    return LayoutBuilder(
      builder: (_, constraints) {
        // When empty (no tags, no text): fill available width so the hint
        // text displays without ellipsis.
        // When typing or has tags: use _inlineWidth (TextPainter-measured,
        // min 60 px) so the TextField grows with the user's input while
        // the SingleChildScrollView scrolls the overflow.
        final tfWidth =
            (hasTags || hasText) ? _inlineWidth : constraints.maxWidth;
        return SizedBox(
          height: 20.0,
          child: SingleChildScrollView(
            scrollDirection: Axis.horizontal,
            controller: _scrollController,
            child: Row(
              crossAxisAlignment: CrossAxisAlignment.center,
              children: [
                ...List.generate(tags.length, (i) {
                  final tag = tags[i];
                  return Padding(
                    padding: EdgeInsetsDirectional.only(end: BTSpacing.xs),
                    child: BTTag(
                      key: ValueKey(tag.effectiveId),
                      label: tag.label,
                      onRemove: (!widget.disabled && isActive)
                          ? () => _removeTag(tag)
                          : null,
                    ),
                  );
                }),
                SizedBox(
                  width: tfWidth,
                  height: 20.0,
                  child: _textField(
                    c,
                    labelColor: labelColor,
                    isFloating: isFloating,
                  ),
                ),
              ],
            ),
          ),
        );
      },
    );
  }

  // ── Build ──────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    if (widget.validator != null) {
      return FormField<List<BTTagItem>>(
        autovalidateMode: AutovalidateMode.disabled,
        validator: (_) => widget.validator?.call(_currentTags),
        builder: (field) => _buildBody(
          context,
          errorText: widget.errorText ?? field.errorText,
        ),
      );
    }
    return _buildBody(context, errorText: widget.errorText);
  }

  Widget _buildBody(BuildContext context, {required String? errorText}) {
    final c = context.btColor;
    final hasError = errorText != null;
    final tags = _currentTags;
    final hasTags = tags.isNotEmpty;
    final isFloating = _isFloating;
    final labelColor = _labelColor(c, hasError: hasError);
    final iconColor = widget.disabled ? c.icon.disabled : c.icon.primary;
    final field = OverlayPortal(
      controller: _overlayController,
      // ── Dropdown overlay ─────────────────────────────────────────────────
      // Use Positioned (screen-absolute coords) instead of
      // CompositedTransformFollower so the dropdown reliably tracks the
      // field's bottom edge even when the field grows (wrap mode, new tag
      // row). _overlayTop / _overlayLeft / _overlayWidth are computed by
      // _syncDropdownPosition (sync, on open) and _refreshDropdownPosition
      // (postFrameCallback, on tag add/remove).
      // _dropdownAbove flips placement when there is insufficient space below.
      overlayChildBuilder: (_) => Positioned(
        top: _dropdownAbove ? null : _overlayTop,
        bottom: _dropdownAbove ? _overlayBottom : null,
        left: _overlayLeft,
        width: _overlayWidth,
        child: ConstrainedBox(
          constraints: BoxConstraints(
            maxHeight: _overlayMaxHeight.clamp(80, double.infinity),
          ),
          child: TapRegion(
          groupId: _tapGroupId,
          onTapOutside: (_) => _close(),
          child: BTDropdownList<T>(
            variant: BTDropdownListVariant.checkbox,
            items: _filteredItems,
            hasSearch: widget.hasSearch,
            searchQuery: _searchQuery,
            emptyLabel: widget.emptyLabel,
            onSearch: widget.hasSearch
                ? (q) => setState(() => _searchQuery = q)
                : null,
            onSelect: _handleDropdownToggle,
          ),
        ),
        ),
      ),
      // ── Field container ──────────────────────────────────────────
      child: TapRegion(
        groupId: _tapGroupId,
        onTapOutside: (_) {
          _focusNode.unfocus();
          _close();
        },
        child: GestureDetector(
          behavior: HitTestBehavior.translucent,
          onTap: widget.disabled
              ? null
              : () => _focusNode.requestFocus(),
          // TweenAnimationBuilder<Decoration> animates ONLY the border
          // color (decoration). The Container is plain (no animation),
          // so height changes when tags are added are instant → no
          // overflow flicker. Width is correct because Container gets
          // tight constraints directly from the parent chain (no Stack
          // indirection that would make constraints loose).
          child: TweenAnimationBuilder<Decoration>(
            tween: DecorationTween(
              end: BoxDecoration(
                color: widget.disabled ? c.bg.subtle : c.bg.primary,
                border: Border.all(
                  color: _borderColor(c, hasError: hasError),
                ),
                borderRadius: BorderRadius.circular(BTRadius.sm),
              ),
            ),
            duration: const Duration(milliseconds: 150),
            curve: const Cubic(0.4, 0, 0.2, 1),
            builder: (_, decoration, child) => Container(
              key: _fieldKey,
              constraints: const BoxConstraints(minHeight: 48),
              padding: EdgeInsets.symmetric(
                horizontal: BTSpacing.sm,
                vertical: BTSpacing.xs,
              ),
              decoration: decoration,
              child: child,
            ),
            // Column(mainAxisAlignment.center) centers the Row in the
            // 48 px floor without explicit vertPad arithmetic:
            //   idle   → Row(20 px) centered → 14 px above/below
            //   float  → Row(36 px) centered →  6 px above/below
            //   >48 px → Column grows, center has no extra effect
            child: Column(
              mainAxisSize: MainAxisSize.min,
              mainAxisAlignment: MainAxisAlignment.center,
              children: [
                Row(
                  crossAxisAlignment: CrossAxisAlignment.center,
                  children: [
                    // ── Left icon ─────────────────────────────
                    if (widget.leftIcon != null) ...[
                      IconTheme(
                        data: IconThemeData(
                          size: 16,
                          color: iconColor,
                        ),
                        child: widget.leftIcon!,
                      ),
                      SizedBox(width: BTSpacing.sm),
                    ],

                    // ── Label + tag content ───────────────────
                    Expanded(
                      child: Column(
                        mainAxisSize: MainAxisSize.min,
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          if (widget.label != null)
                            ClipRect(
                              child: AnimatedAlign(
                                duration: const Duration(
                                  milliseconds: 150,
                                ),
                                curve: const Cubic(0.4, 0, 0.2, 1),
                                alignment: AlignmentDirectional.topStart,
                                heightFactor:
                                    isFloating ? 1.0 : 0.0,
                                child: Text.rich(
                                  TextSpan(
                                    children: [
                                      TextSpan(text: widget.label),
                                      if (widget.required)
                                        TextSpan(
                                          text: ' *',
                                          style: TextStyle(
                                            color: c.ext.error,
                                          ),
                                        ),
                                    ],
                                  ),
                                  strutStyle: StrutStyle(
                                    fontFamily:
                                        BTTypography.fontFamily,
                                    fontSize: 12.0,
                                    height: 4 / 3,
                                    forceStrutHeight: true,
                                  ),
                                  style: TextStyle(
                                    fontFamily:
                                        BTTypography.fontFamily,
                                    fontSize: 12.0,
                                    fontWeight: FontWeight.w500,
                                    height: 4 / 3,
                                    letterSpacing: 0,
                                    color: labelColor,
                                  ),
                                ),
                              ),
                            ),
                          if (widget.type ==
                              BTInputMultipleFieldType.scroll)
                            _buildScrollContent(
                              tags,
                              c,
                              labelColor: labelColor,
                              isFloating: isFloating,
                            )
                          else
                            _buildWrapContent(
                              tags,
                              c,
                              labelColor: labelColor,
                              isFloating: isFloating,
                            ),
                        ],
                      ),
                    ),

                    // ── Suffix: clear × + chevron ─────────────
                    if (!widget.disabled) ...[
                      SizedBox(width: BTSpacing.sm),
                      ClipRect(
                        child: AnimatedAlign(
                          duration:
                              const Duration(milliseconds: 150),
                          curve: const Cubic(0.4, 0, 0.2, 1),
                          alignment: AlignmentDirectional.centerEnd,
                          widthFactor:
                              ((_isOpen || _isFocused) && hasTags)
                                  ? 1.0
                                  : 0.0,
                          child: Row(
                            mainAxisSize: MainAxisSize.min,
                            children: [
                              GestureDetector(
                                onTap: _clearAll,
                                child: Icon(
                                  Icons.cancel,
                                  size: 16,
                                  color: iconColor,
                                ),
                              ),
                              SizedBox(width: BTSpacing.xs),
                            ],
                          ),
                        ),
                      ),
                      GestureDetector(
                        onTap: _toggle,
                        child: Icon(
                          _isOpen
                              ? Icons.keyboard_arrow_up
                              : Icons.keyboard_arrow_down,
                          size: 16,
                          color: iconColor,
                        ),
                      ),
                    ],
                  ],
                ),
              ],
            ),
          ),
        ),
      ),
    );

    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        field,
        if (hasError) ...[
          SizedBox(height: 4.0),
          Text(
            errorText,
            style: TextStyle(
              fontFamily: BTTypography.fontFamily,
              fontSize: 12.0,
              fontWeight: FontWeight.w500,
              height: 4 / 3,
              color: c.ext.error,
            ),
          ),
        ] else if (widget.helperText != null) ...[
          SizedBox(height: 4.0),
          Text(
            widget.helperText!,
            style: TextStyle(
              fontFamily: BTTypography.fontFamily,
              fontSize: 12.0,
              fontWeight: FontWeight.w500,
              height: 4 / 3,
              color: c.text.secondary,
            ),
          ),
        ],
      ],
    );
  }
}

/// BTInputMultipleOptions — checkbox group form field.
/// Figma M node 859-2091.
///
/// Renders an optional title row above a [Wrap] grid of [BTCheckbox] items.
/// Multiple items can be selected simultaneously; the selected set is kept
/// in [values]. Setting [errorText] turns the title and every checkbox red
/// and shows validation text below.
///
/// ## Usage
/// ```dart
/// BTInputMultipleOptions<String>(
///   label: 'Frameworks',
///   required: true,
///   items: const [
///     BTInputOptionsItem(value: 'flutter', label: 'Flutter'),
///     BTInputOptionsItem(value: 'react',   label: 'React'),
///     BTInputOptionsItem(value: 'vue',     label: 'Vue'),
///   ],
///   values: _selected,
///   onChanged: (v) => setState(() => _selected = v),
/// )
///
/// // Form validation
/// BTInputMultipleOptions<String>(
///   label: 'Role',
///   required: true,
///   items: _roleItems,
///   values: _roles,
///   onChanged: (v) => setState(() => _roles = v),
///   validator: (v) => v.isEmpty ? 'Pilih setidaknya satu' : null,
/// )
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import '../../checkbox/checkbox.widget.dart';
import 'package:btech_ui/src/components/molecules/input/input_options.types.dart';
import 'package:flutter/material.dart';

class BTInputMultipleOptions<T> extends StatefulWidget {
  const BTInputMultipleOptions({
    required this.items,
    this.label,
    this.required = false,
    this.disabled = false,
    this.errorText,
    this.helperText,
    this.values = const {},
    this.onChanged,
    this.validator,
    super.key,
  });

  /// Checkbox options shown in the wrap grid.
  final List<BTInputOptionsItem<T>> items;

  /// Title shown above the options.
  /// Renders in [text.secondary] by default;
  /// [ext.error] when [errorText] is set.
  final String? label;

  /// Appends " *" (red) to [label] when true.
  final bool required;

  /// Disables all interaction and applies disabled visual state.
  final bool disabled;

  /// When set, shows error styling on the title and all checkboxes,
  /// and renders this string below the options in [ext.error] color.
  final String? errorText;

  /// Helper text shown below the options when there is no error.
  final String? helperText;

  /// Currently selected values (empty set = nothing selected).
  final Set<T> values;

  /// Called with the updated [Set] every time a checkbox is toggled.
  final ValueChanged<Set<T>>? onChanged;

  /// Validator for [Form.validate] integration.
  final FormFieldValidator<Set<T>>? validator;

  @override
  State<BTInputMultipleOptions<T>> createState() =>
      _BTInputMultipleOptionsState<T>();
}

class _BTInputMultipleOptionsState<T>
    extends State<BTInputMultipleOptions<T>> {
  late Set<T> _selectedValues;

  @override
  void initState() {
    super.initState();
    _selectedValues = Set<T>.from(widget.values);
  }

  @override
  void didUpdateWidget(BTInputMultipleOptions<T> old) {
    super.didUpdateWidget(old);
    if (widget.values != old.values) {
      _selectedValues = Set<T>.from(widget.values);
    }
  }

  void _handleToggle(T value) {
    if (widget.disabled) return;
    final updated = Set<T>.from(_selectedValues);
    if (updated.contains(value)) {
      updated.remove(value);
    } else {
      updated.add(value);
    }
    setState(() => _selectedValues = updated);
    widget.onChanged?.call(updated);
  }

  @override
  Widget build(BuildContext context) {
    if (widget.validator != null) {
      return FormField<Set<T>>(
        autovalidateMode: AutovalidateMode.disabled,
        validator: (_) => widget.validator?.call(_selectedValues),
        builder: (field) =>
            _buildBody(context, errorText: widget.errorText ?? field.errorText),
      );
    }
    return _buildBody(context, errorText: widget.errorText);
  }

  Widget _buildBody(BuildContext context, {required String? errorText}) {
    final c = context.btColor;
    final hasError = errorText != null;

    // Title color:
    //   error    → ext.error
    //   disabled → text.primary
    //   default  → text.secondary
    final Color labelColor;
    if (hasError) {
      labelColor = c.ext.error;
    } else if (widget.disabled) {
      labelColor = c.text.primary;
    } else {
      labelColor = c.text.secondary;
    }

    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        // ── Title ────────────────────────────────────────────────────────────
        if (widget.label != null) ...[
          Text.rich(
            TextSpan(
              children: [
                TextSpan(text: widget.label),
                if (widget.required)
                  TextSpan(
                    text: ' *',
                    style: TextStyle(color: c.ext.error),
                  ),
              ],
            ),
            style: TextStyle(
              fontFamily: BTTypography.fontFamily,
              fontSize: 14.0,
              fontWeight: FontWeight.w500,
              height: 16 / 14,
              color: labelColor,
            ),
          ),
          SizedBox(height: 4.0),
        ],

        // ── Checkbox wrap grid ───────────────────────────────────────────────
        // Figma gap-[spacing.sm=8px]. BTCheckbox has no outer padding,
        // so each item is wrapped in Padding(all:4) to match Figma's
        // p-[spacing.xs=4px] per cell. Visual gap = 4+8+4 = 16px.
        Wrap(
          spacing: 8.0,
          runSpacing: 8.0,
          children: widget.items.map((item) {
            return Padding(
              padding: EdgeInsets.all(4.0),
              child: BTCheckbox(
                checked: _selectedValues.contains(item.value),
                label: item.label,
                disabled: widget.disabled,
                // Error only on items that are NOT yet selected —
                // selected items are already correct, only unselected
                // ones need the user's attention.
                error: hasError && !_selectedValues.contains(item.value),
                onChanged: widget.disabled
                    ? null
                    : (_) => _handleToggle(item.value),
              ),
            );
          }).toList(),
        ),

        // ── Validation / helper text ──────────────────────────────────────────
        if (hasError) ...[
          SizedBox(height: 4.0),
          Text(
            errorText,
            style: TextStyle(
              fontFamily: BTTypography.fontFamily,
              fontSize: 12.0,
              fontWeight: FontWeight.w500,
              height: 4 / 3,
              color: c.ext.error,
            ),
          ),
        ] else if (widget.helperText != null) ...[
          SizedBox(height: 4.0),
          Text(
            widget.helperText!,
            style: TextStyle(
              fontFamily: BTTypography.fontFamily,
              fontSize: 12.0,
              fontWeight: FontWeight.w500,
              height: 4 / 3,
              color: c.text.secondary,
            ),
          ),
        ],
      ],
    );
  }
}

/// BTInputSearch — compact search field (Figma M node 750-2949).
///
/// Height: ~40 px (12 px vertical padding + 16 px line-height).
/// Font: 12 px / medium (fontSize.xs). No floating label.
///
/// - Fixed left search icon.
/// - Cancel (×) appears when focused + has text.
/// - Optional [suffix] slot to the right of cancel.
/// - Error and helper text below the field.
///
/// ## Usage
/// ```dart
/// BTInputSearch(
///   placeholder: 'Search',
///   onSearch: (q) => _filter(q),
///   onChanged: (v) => setState(() => _query = v),
/// )
///
/// // Error state
/// BTInputSearch(errorText: 'No results found.')
///
/// // With right icon slot
/// BTInputSearch(suffix: Icon(Icons.tune, size: 16))
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import 'package:flutter/material.dart';
import 'package:flutter_svg/flutter_svg.dart';

class BTInputSearch extends StatefulWidget {
  const BTInputSearch({
    this.value,
    this.controller,
    this.focusNode,
    this.placeholder = 'Search',
    this.disabled = false,
    this.readOnly = false,
    this.errorText,
    this.helperText,
    this.suffix,
    this.onChanged,
    this.onSearch,
    this.onClear,
    this.validator,
    this.alwaysShowClear = false,
    super.key,
  });

  /// Initial / controlled text value.
  final String? value;
  final TextEditingController? controller;
  final FocusNode? focusNode;

  /// Placeholder shown when empty. Defaults to `'Search'`.
  final String placeholder;

  /// Disables all interaction and applies disabled visual state.
  final bool disabled;

  /// Blocks interaction but keeps normal (non-greyed) colours.
  final bool readOnly;

  /// When set, shows the error border and text below the field.
  final String? errorText;

  /// Helper text shown below the field when there is no error.
  final String? helperText;

  /// Optional widget appended to the right of the clear button.
  final Widget? suffix;

  final ValueChanged<String>? onChanged;

  /// Called when the user submits (presses Enter / search action).
  final ValueChanged<String>? onSearch;

  /// Called when the × clear button is tapped.
  final VoidCallback? onClear;

  /// Validator for [Form.validate] integration.
  final FormFieldValidator<String>? validator;

  /// When `true`, the clear (×) button is always visible regardless of focus
  /// or text content — useful when the field is used as a dismissable overlay
  /// (e.g. BTDataTable expanded search). When `false` (default), clear only
  /// shows while focused with non-empty text.
  final bool alwaysShowClear;

  @override
  State<BTInputSearch> createState() => _BTInputSearchState();
}

class _BTInputSearchState extends State<BTInputSearch> {
  late TextEditingController _controller;
  late FocusNode _focusNode;
  bool _isFocused = false;
  bool _ownsController = false;
  bool _ownsFocusNode = false;

  @override
  void initState() {
    super.initState();
    _controller =
        widget.controller ?? TextEditingController(text: widget.value);
    _ownsController = widget.controller == null;
    _focusNode = widget.focusNode ?? FocusNode();
    _ownsFocusNode = widget.focusNode == null;
    _focusNode.addListener(_handleFocusChange);
    _controller.addListener(_handleValueChange);
  }

  @override
  void didUpdateWidget(BTInputSearch old) {
    super.didUpdateWidget(old);
    final v = widget.value;
    if (v != null && v != _controller.text) {
      _controller.value = _controller.value.copyWith(
        text: v,
        selection: _controller.selection.baseOffset <= v.length
            ? _controller.selection
            : TextSelection.collapsed(offset: v.length),
      );
    }
  }

  @override
  void dispose() {
    _focusNode.removeListener(_handleFocusChange);
    _controller.removeListener(_handleValueChange);
    if (_ownsController) _controller.dispose();
    if (_ownsFocusNode) _focusNode.dispose();
    super.dispose();
  }

  void _handleFocusChange() =>
      setState(() => _isFocused = _focusNode.hasFocus);
  void _handleValueChange() => setState(() {});

  bool get _isEmpty => _controller.text.isEmpty;
  bool get _showClear {
    if (widget.disabled || widget.readOnly) return false;
    // alwaysShowClear: visible regardless of focus/text — even when empty.
    if (widget.alwaysShowClear) return true;
    return _isFocused && !_isEmpty;
  }

  void _onClear() {
    _controller.clear();
    widget.onChanged?.call('');
    widget.onClear?.call();
  }

  // ── Color helpers ─────────────────────────────────────────────────────────

  Color _borderColor(BTColorTheme c, {required bool hasError}) {
    if (widget.disabled) return c.border.primary;
    if (hasError) return c.ext.error;
    if (_isFocused) return c.brand.primary;
    return c.border.primary;
  }

  Color _placeholderColor(BTColorTheme c, {required bool hasError}) {
    if (widget.disabled) return c.text.disabled;
    if (hasError) return c.ext.error;
    return c.text.secondary;
  }

  // ── Build ─────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    if (widget.validator != null) {
      return TapRegion(
        onTapOutside: (_) => _focusNode.unfocus(),
        child: FormField<String>(
          autovalidateMode: AutovalidateMode.disabled,
          validator: (_) => widget.validator!(_controller.text),
          builder: (field) => _buildBody(
            context,
            errorText: widget.errorText ?? field.errorText,
          ),
        ),
      );
    }
    return TapRegion(
      onTapOutside: (_) => _focusNode.unfocus(),
      child: _buildBody(context, errorText: widget.errorText),
    );
  }

  Widget _buildBody(BuildContext context, {required String? errorText}) {
    final c = context.btColor;
    final hasError = errorText != null;
    final iconColor = widget.disabled ? c.text.disabled : c.icon.primary;

    final field = GestureDetector(
      behavior: HitTestBehavior.translucent,
      onTap: (widget.disabled || widget.readOnly)
          ? null
          : _focusNode.requestFocus,
      child: AnimatedContainer(
        duration: const Duration(milliseconds: 150),
        curve: const Cubic(0.4, 0, 0.2, 1),
        clipBehavior: Clip.hardEdge,
        decoration: BoxDecoration(
          color: widget.disabled ? c.bg.subtle : c.bg.primary,
          border: Border.all(
            color: _borderColor(c, hasError: hasError),
            width: 1,
          ),
          borderRadius: BorderRadius.circular(BTRadius.sm),
        ),
        // Figma: px-8 py-12 → compact 40 px total height
        padding: EdgeInsets.symmetric(horizontal: 8.0, vertical: 12.0),
        child: Row(
          crossAxisAlignment: CrossAxisAlignment.center,
          children: [
            SizedBox(
              width: 16.0,
              height: 16.0,
              child: Center(
                child: SvgPicture.asset(
                  'packages/btech_assets/assets/icons/input_search/search.svg',
                  width: 12.0,
                  height: 12.0,
                  colorFilter: ColorFilter.mode(iconColor, BlendMode.srcIn),
                ),
              ),
            ),
            SizedBox(width: 8.0),
            Expanded(
              child: IgnorePointer(
                ignoring: widget.readOnly,
                child: TextField(
                  controller: _controller,
                  focusNode: _focusNode,
                  enabled: !widget.disabled,
                  readOnly: widget.readOnly,
                  cursorHeight: 12,
                  maxLines: 1,
                  onChanged: widget.onChanged,
                  onSubmitted: widget.onSearch,
                  style: TextStyle(
                    fontFamily: BTTypography.fontFamily,
                    fontSize: 12.0,
                    fontWeight: FontWeight.w500,
                    height: 4 / 3,
                    color: widget.disabled
                        ? c.text.disabled
                        : c.text.primary,
                  ),
                  decoration: InputDecoration(
                    isCollapsed: true,
                    border: InputBorder.none,
                    hintText: widget.placeholder,
                    hintStyle: TextStyle(
                      fontFamily: BTTypography.fontFamily,
                      fontSize: 12.0,
                      fontWeight: FontWeight.w500,
                      height: 4 / 3,
                      color: _placeholderColor(c, hasError: hasError),
                    ),
                    counterText: '',
                  ),
                ),
              ),
            ),
            ClipRect(
              child: AnimatedAlign(
                duration: const Duration(milliseconds: 150),
                curve: const Cubic(0.4, 0, 0.2, 1),
                alignment: AlignmentDirectional.centerEnd,
                widthFactor: _showClear ? 1.0 : 0.0,
                child: Row(
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    SizedBox(width: 8.0),
                    GestureDetector(
                      onTap: _onClear,
                      child: Icon(
                        Icons.cancel,
                        size: 16,
                        color: c.icon.primary,
                      ),
                    ),
                  ],
                ),
              ),
            ),
            if (widget.suffix != null) ...[
              SizedBox(width: 8.0),
              widget.suffix!,
            ],
          ],
        ),
      ),
    );

    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        field,
        if (hasError)
          Padding(
            padding: EdgeInsets.only(top: 4.0),
            child: Text(
              errorText,
              style: TextStyle(
                fontFamily: BTTypography.fontFamily,
                fontSize: 12.0,
                fontWeight: FontWeight.w500,
                height: 4 / 3,
                color: c.ext.error,
              ),
            ),
          )
        else if (widget.helperText != null)
          Padding(
            padding: EdgeInsets.only(top: 4.0),
            child: Text(
              widget.helperText!,
              style: TextStyle(
                fontFamily: BTTypography.fontFamily,
                fontSize: 12.0,
                fontWeight: FontWeight.w500,
                height: 4 / 3,
                color: c.text.secondary,
              ),
            ),
          ),
      ],
    );
  }
}

/// Data model for a single option inside [BTInputSingleOptions].
class BTInputSingleOptionsItem<T> {
