/// BTInputSingleOptions — radio-button group form field.
/// Figma M node 702-3422.
///
/// Renders an optional title row above a [Wrap] grid of [BTRadioButton] items.
/// Items reflow into multiple rows automatically. Setting [errorText] turns the
/// title and every radio button red and shows validation text below.
///
/// ## Usage
/// ```dart
/// BTInputSingleOptions<String>(
///   label: 'Gender',
///   required: true,
///   items: const [
///     BTInputSingleOptionsItem(value: 'male',   label: 'Male'),
///     BTInputSingleOptionsItem(value: 'female', label: 'Female'),
///     BTInputSingleOptionsItem(value: 'other',  label: 'Other'),
///   ],
///   value: _gender,
///   onChanged: (v) => setState(() => _gender = v),
/// )
///
/// // Form validation
/// BTInputSingleOptions<String>(
///   label: 'Role',
///   required: true,
///   items: _roleItems,
///   value: _role,
///   onChanged: (v) => setState(() => _role = v),
///   validator: (v) => v == null ? 'Pilih salah satu' : null,
/// )
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import '../../radio-button/radio_button.widget.dart';
import 'package:btech_ui/src/components/molecules/input/input_options.types.dart';
import 'package:flutter/material.dart';

class BTInputSingleOptions<T> extends StatefulWidget {
  const BTInputSingleOptions({
    required this.items,
    this.label,
    this.required = false,
    this.disabled = false,
    this.errorText,
    this.helperText,
    this.value,
    this.onChanged,
    this.validator,
    super.key,
  });

  /// Radio options shown in the wrap grid.
  final List<BTInputSingleOptionsItem<T>> items;

  /// Title shown above the options.
  /// Renders in [text.secondary] by default;
  /// [ext.error] when [errorText] is set.
  final String? label;

  /// Appends " *" (red) to [label] when true.
  final bool required;

  /// Disables all interaction and applies disabled visual state to every radio.
  final bool disabled;

  /// When set, shows error styling on the title and all radio buttons,
  /// and renders this string below the options in [ext.error] color.
  final String? errorText;

  /// Helper text shown below the options when there is no error.
  final String? helperText;

  /// Currently selected value. `null` means no option is selected.
  final T? value;

  /// Called when the user selects an option.
  final ValueChanged<T?>? onChanged;

  /// Validator for [Form.validate] integration.
  final FormFieldValidator<T?>? validator;

  @override
  State<BTInputSingleOptions<T>> createState() =>
      _BTInputSingleOptionsState<T>();
}

class _BTInputSingleOptionsState<T> extends State<BTInputSingleOptions<T>> {
  T? _selectedValue;

  @override
  void initState() {
    super.initState();
    _selectedValue = widget.value;
  }

  @override
  void didUpdateWidget(BTInputSingleOptions<T> old) {
    super.didUpdateWidget(old);
    if (widget.value != old.value) _selectedValue = widget.value;
  }

  void _handleChange(T v) {
    if (widget.disabled) return;
    setState(() => _selectedValue = v);
    widget.onChanged?.call(v);
  }

  @override
  Widget build(BuildContext context) {
    if (widget.validator != null) {
      return FormField<T?>(
        autovalidateMode: AutovalidateMode.disabled,
        validator: (_) => widget.validator?.call(_selectedValue),
        builder: (field) =>
            _buildBody(context, errorText: widget.errorText ?? field.errorText),
      );
    }
    return _buildBody(context, errorText: widget.errorText);
  }

  Widget _buildBody(BuildContext context, {required String? errorText}) {
    final c = context.btColor;
    final hasError = errorText != null;

    // Title color:
    //   error    → ext.error
    //   disabled → text.primary
    //   default  → text.secondary
    final Color labelColor;
    if (hasError) {
      labelColor = c.ext.error;
    } else if (widget.disabled) {
      labelColor = c.text.primary;
    } else {
      labelColor = c.text.secondary;
    }

    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        // ── Title ────────────────────────────────────────────────────────────
        if (widget.label != null) ...[
          Text.rich(
            TextSpan(
              children: [
                TextSpan(text: widget.label),
                if (widget.required)
                  TextSpan(
                    text: ' *',
                    style: TextStyle(color: c.ext.error),
                  ),
              ],
            ),
            style: TextStyle(
              fontFamily: BTTypography.fontFamily,
              fontSize: 14.0,
              fontWeight: FontWeight.w500,
              height: 16 / 14,
              color: labelColor,
            ),
          ),
          SizedBox(height: 4.0),
        ],

        // ── Radio wrap grid ──────────────────────────────────────────────────
        // spacing/runSpacing: 8 matches Figma gap-[spacing.sm=8px].
        // BTRadioButton has 4px padding all sides; visual content gap =
        // 4+8+4 = 16px — same as CSS gap:8px between element boxes.
        Wrap(
          spacing: 8.0,
          runSpacing: 8.0,
          children: widget.items.map((item) {
            return BTRadioButton<T?>(
              groupValue: _selectedValue,
              value: item.value,
              label: item.label,
              disabled: widget.disabled,
              error: hasError,
              onChanged: (v) {
                if (v != null) _handleChange(v);
              },
            );
          }).toList(),
        ),

        // ── Validation / helper text ──────────────────────────────────────────
        if (hasError) ...[
          SizedBox(height: 4.0),
          Text(
            errorText,
            style: TextStyle(
              fontFamily: BTTypography.fontFamily,
              fontSize: 12.0,
              fontWeight: FontWeight.w500,
              height: 4 / 3,
              color: c.ext.error,
            ),
          ),
        ] else if (widget.helperText != null) ...[
          SizedBox(height: 4.0),
          Text(
            widget.helperText!,
            style: TextStyle(
              fontFamily: BTTypography.fontFamily,
              fontSize: 12.0,
              fontWeight: FontWeight.w500,
              height: 4 / 3,
              color: c.text.secondary,
            ),
          ),
        ],
      ],
    );
  }
}

import 'package:btech_tokens/btech_tokens.dart';
import '../../scrollbar/scrollbar.widget.dart';
import 'package:flutter/material.dart';

/// Auto-expanding multiline text input — the btech textarea molecule.
///
/// The field starts at 80 px tall and grows smoothly (150 ms ease) as the
/// user types new lines. It caps at 160 px; once content exceeds that height
/// a scrollbar appears on the right edge **below** the floating label.
///
/// When [label] is set it floats to the top-left (12 px, text.secondary) once
/// the field is focused or has content, matching the BTInput floating-label
/// pattern.
///
/// The clear (×) button appears in the "Filled" state (not focused, has
/// content, no error) and sits at top-right inside the field.
///
/// Pass [validator] to integrate with Flutter's [Form] /
/// [GlobalKey<FormState>] system — same as [BTInput].
///
/// ## Usage
/// ```dart
/// // Basic
/// BTInputTextArea(
///   label: 'Description',
///   placeholder: 'Write something here...',
///   onChanged: (v) => setState(() => _desc = v),
/// )
///
/// // With character counter
/// BTInputTextArea(
///   label: 'Bio',
///   maxLength: 200,
///   onChanged: (v) => setState(() => _bio = v),
///   onClear: () => setState(() => _bio = ''),
/// )
///
/// // Form validation
/// Form(
///   key: _formKey,
///   child: Column(children: [
///     BTInputTextArea(
///       label: 'Notes',
///       required: true,
///       validator: (v) => v!.trim().isEmpty ? 'Wajib diisi' : null,
///     ),
///     BTButton(
///       label: 'Submit',
///       onPressed: () => _formKey.currentState!.validate(),
///     ),
///   ]),
/// )
/// ```
class BTInputTextArea extends StatefulWidget {
  const BTInputTextArea({
    this.value,
    this.controller,
    this.focusNode,
    this.label,
    this.placeholder,
    this.required = false,
    this.disabled = false,
    this.errorText,
    this.maxLength,
    this.onChanged,
    this.onClear,
    this.validator,
    super.key,
  });

  /// Pre-filled text value. Synced into the internal controller when changed.
  final String? value;

  /// Optional external controller — caller is responsible for disposal.
  final TextEditingController? controller;

  /// Optional external focus node — caller is responsible for disposal.
  final FocusNode? focusNode;

  /// Label that floats to the top-left when focused or filled.
  final String? label;

  /// Hint text shown inside the text area when the label is floating.
  final String? placeholder;

  /// Appends " *" to [label] to signal a required field.
  final bool required;

  /// Disables editing and applies the disabled visual state.
  final bool disabled;

  /// When set, shows the error border and text below the field.
  final String? errorText;

  /// Enables the character counter below-right. Shows `current/max`.
  final int? maxLength;

  final ValueChanged<String>? onChanged;

  /// Called when the user taps the clear (×) button. Use this to reset the
  /// external state — the internal controller is cleared automatically.
  final VoidCallback? onClear;

  /// Integrates with [Form.validate()]. Receives the current text.
  final FormFieldValidator<String>? validator;

  @override
  State<BTInputTextArea> createState() => _BTInputTextAreaState();
}

class _BTInputTextAreaState extends State<BTInputTextArea> {
  late TextEditingController _controller;
  late FocusNode _focusNode;
  final ScrollController _scrollController = ScrollController();

  // GlobalKey on the inner Padding (inside SingleChildScrollView) so we can
  // measure the natural content height — SCSV gives its child unbounded
  // vertical space, so box.size.height == real content height, not viewport.
  final _contentKey = GlobalKey();

  bool _isFocused = false;
  bool _ownsController = false;
  bool _ownsFocusNode = false;

  /// Animated field height — grows from [_kMinHeight] to [_kMaxHeight].
  double _fieldHeight = _kMinHeight;

  /// True once content height exceeds [_kMaxHeight]; enables the scrollbar.
  bool _showScrollbar = false;

  static const double _kMinHeight = 80;
  static const double _kMaxHeight = 160;

  // Floating label: 12 px font × (4/3) line-height = 16 px.
  static const double _kLabelHeight = 16;
  static const double _kPaddingVert = 8;

  // ── Lifecycle ──────────────────────────────────────────────────────────────

  @override
  void initState() {
    super.initState();
    _controller =
        widget.controller ?? TextEditingController(text: widget.value);
    _ownsController = widget.controller == null;
    _focusNode = widget.focusNode ?? FocusNode();
    _ownsFocusNode = widget.focusNode == null;

    _focusNode.addListener(_handleFocusChange);
    _controller.addListener(_handleValueChange);

    // Measure after the first frame so an initial value is sized correctly.
    WidgetsBinding.instance
        .addPostFrameCallback((_) => _measureContentHeight());
  }

  @override
  void didUpdateWidget(BTInputTextArea old) {
    super.didUpdateWidget(old);
    final newValue = widget.value;
    if (newValue != null && newValue != _controller.text) {
      _controller.value = _controller.value.copyWith(
        text: newValue,
        selection: _controller.selection.baseOffset <= newValue.length
            ? _controller.selection
            : TextSelection.collapsed(offset: newValue.length),
      );
    }
  }

  @override
  void dispose() {
    _focusNode.removeListener(_handleFocusChange);
    _controller.removeListener(_handleValueChange);
    if (_ownsController) _controller.dispose();
    if (_ownsFocusNode) _focusNode.dispose();
    _scrollController.dispose();
    super.dispose();
  }

  // ── Event handlers ─────────────────────────────────────────────────────────

  void _handleFocusChange() =>
      setState(() => _isFocused = _focusNode.hasFocus);

  void _handleValueChange() {
    // Rebuild immediately (label float, hint, counter), then remeasure.
    setState(() {});
    WidgetsBinding.instance
        .addPostFrameCallback((_) => _measureContentHeight());
  }

  /// Reads the natural height of the inner Padding widget.
  ///
  /// SingleChildScrollView gives its child UNBOUNDED vertical space, so
  /// `box.size.height` equals the real content height — not the viewport.
  /// This lets us correctly shrink the field when lines are deleted.
  void _measureContentHeight() {
    if (!mounted) return;
    final box = _contentKey.currentContext?.findRenderObject() as RenderBox?;
    if (box == null || !box.hasSize) return;

    // AnimatedPositioned owns the top offset, so box.size.height is only the
    // bottom region (text + bottom padding). Add the header height back so
    // _fieldHeight accounts for the full visual space.
    final headerH = (widget.label != null && _isFloating)
        ? (_kPaddingVert + _kLabelHeight)
        : _kPaddingVert;
    final totalH = headerH + box.size.height;
    final newFieldH = totalH.clamp(_kMinHeight, _kMaxHeight);
    final newShowScrollbar = totalH > _kMaxHeight;

    if (newFieldH != _fieldHeight || newShowScrollbar != _showScrollbar) {
      setState(() {
        _fieldHeight = newFieldH;
        _showScrollbar = newShowScrollbar;
      });
    }
  }

  void _onClear() {
    _controller.clear();
    widget.onChanged?.call('');
    widget.onClear?.call();
    // _controller.clear() fires _handleValueChange which schedules
    // _measureContentHeight, so an explicit call here is redundant but safe.
    WidgetsBinding.instance
        .addPostFrameCallback((_) => _measureContentHeight());
  }

  // ── State helpers ──────────────────────────────────────────────────────────

  bool get _isEmpty => _controller.text.isEmpty;

  /// Label floats to top-left when focused or field has content.
  bool get _isFloating => _isFocused || !_isEmpty;

  // ── Color helpers ──────────────────────────────────────────────────────────

  Color _borderColor(BTColorTheme c, {required bool hasError}) {
    if (widget.disabled) return c.border.primary;
    if (hasError) return c.ext.error;
    if (_isFocused) return c.brand.primary;
    return c.border.primary;
  }

  /// Figma textarea: disabled label uses text.primary (not text.disabled).
  Color _labelColor(BTColorTheme c, {required bool hasError}) {
    if (widget.disabled) return c.text.primary;
    if (hasError) return c.ext.error;
    return c.text.secondary;
  }

  // ── Build ──────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    if (widget.validator != null) {
      return TapRegion(
        onTapOutside: (_) => _focusNode.unfocus(),
        child: FormField<String>(
          autovalidateMode: AutovalidateMode.disabled,
          validator: (_) => widget.validator!(_controller.text),
          builder: (field) => _buildBody(
            context,
            errorText: widget.errorText ?? field.errorText,
          ),
        ),
      );
    }
    return TapRegion(
      onTapOutside: (_) => _focusNode.unfocus(),
      child: _buildBody(context, errorText: widget.errorText),
    );
  }

  Widget _buildBody(BuildContext context, {required String? errorText}) {
    final c = context.btColor;
    final hasError = errorText != null;
    final hasLabel = widget.label != null;
    final labelText = widget.label ?? '';

    // Clear button: visible when focused, has content, and not disabled.
    // Error state does NOT suppress it — user should still be able to clear.
    final showClear = _isFocused && !_isEmpty && !widget.disabled;

    // Right padding of the content column.
    // Space is reserved as soon as the field is focused (regardless of
    // content) so the text does not reflow when the clear button slides in.
    //   focused (clear button slot reserved): 8 (inset) + 16 (icon) + 4 = 28 px
    //   scrollbar only:                       8 (standard) + 5 (thumb)  = 13 px
    //   default:                              8 px
    final rightPad = (_isFocused && !widget.disabled)
        ? 28.0
        : (_showScrollbar ? 13.0 : 8.0);

    final decoration = BoxDecoration(
      color: widget.disabled ? c.bg.subtle : c.bg.primary,
      border: Border.all(
        color: _borderColor(c, hasError: hasError),
        width: 1,
      ),
      borderRadius: BorderRadius.circular(BTRadius.sm), // 8 px
    );

    // Scrollbar track starts below the floating label:
    //   top-padding (8) + label height (16) = 24 px from the container top.
    // When _showScrollbar is true the field always has content → label is
    // floating, so this offset is constant at 24 px for labelled fields.
    final scrollbarTopOffset =
        hasLabel ? (_kPaddingVert + _kLabelHeight) : _kPaddingVert;

    // ── Animated field container ───────────────────────────────────────────
    // AnimatedContainer drives height from _kMinHeight (80) to _kMaxHeight
    // (160) as content grows. Positioned.fill gives SingleChildScrollView a
    // bounded constraint so it can clip and scroll its content.
    Widget field = AnimatedContainer(
      duration: const Duration(milliseconds: 150),
      curve: const Cubic(0.4, 0, 0.2, 1),
      height: _fieldHeight,
      decoration: decoration,
      child: Stack(
        clipBehavior: Clip.hardEdge,
        children: [
          // ── Scrollable content ─────────────────────────────────────────
          // AnimatedPositioned top = header height (8 or 24 px). The SCSV
          // physically starts BELOW the floating label, so text can never
          // scroll up behind the pinned label overlay.
          AnimatedPositioned(
            duration: const Duration(milliseconds: 150),
            curve: const Cubic(0.4, 0, 0.2, 1),
            top: (hasLabel && _isFloating)
                ? (_kPaddingVert + _kLabelHeight)
                : _kPaddingVert,
            left: 0,
            right: 0,
            bottom: 0,
            child: GestureDetector(
              behavior: HitTestBehavior.translucent,
              onTap: widget.disabled ? null : _focusNode.requestFocus,
              child: SingleChildScrollView(
                controller: _scrollController,
                physics: _showScrollbar
                    ? const ClampingScrollPhysics()
                    : const NeverScrollableScrollPhysics(),
                // top: 0 — header offset is owned by AnimatedPositioned above.
                // GlobalKey: SCSV gives unbounded height so box.size.height
                // equals real content height (text + bottom padding).
                child: AnimatedPadding(
                  key: _contentKey,
                  duration: const Duration(milliseconds: 150),
                  curve: const Cubic(0.4, 0, 0.2, 1),
                  padding: EdgeInsets.only(
                    left: 8.0,
                    top: 0,
                    right: rightPad,
                    bottom: _kPaddingVert,
                  ),
                  child: TextField(
                    controller: _controller,
                    focusNode: _focusNode,
                    enabled: !widget.disabled,
                    maxLines: null,
                    scrollPhysics: const NeverScrollableScrollPhysics(),
                    maxLength: widget.maxLength,
                    keyboardType: TextInputType.multiline,
                    textAlignVertical: TextAlignVertical.top,
                    cursorHeight: 14,
                    onChanged: widget.onChanged,
                    style: TextStyle(
                      fontFamily: BTTypography.fontFamily,
                      fontSize: 14.0,
                      fontWeight: FontWeight.w500,
                      height: 8 / 7, // 16 px / 14 px
                      color: widget.disabled
                          ? c.text.disabled
                          : c.text.primary,
                    ),
                    decoration: InputDecoration(
                      isCollapsed: true,
                      border: InputBorder.none,
                      // When label floats: show placeholder hint.
                      // When label is at rest: label text acts as hint.
                      hintText: hasLabel
                          ? (_isFloating ? widget.placeholder : widget.label)
                          : widget.placeholder,
                      hintStyle: TextStyle(
                        fontFamily: BTTypography.fontFamily,
                        fontSize: 14.0,
                        fontWeight: FontWeight.w500,
                        height: 8 / 7,
                        color: (hasLabel && !_isFloating)
                            ? _labelColor(c, hasError: hasError)
                            : c.text.tertiary,
                      ),
                      // Suppress built-in Material counter —
                      // we render our own below the field.
                      counterText: '',
                    ),
                  ),
                ),
              ),
            ),
          ),

          // ── Pinned floating label ─────────────────────────────────────────
          // Positioned outside the ScrollView so it never scrolls. Uses the
          // same ClipRect + heightFactor collapse as BTInput's floating label.
          // rightPad matches the scrollable content right margin so long
          // labels truncate before reaching the clear button slot.
          if (hasLabel)
            Positioned(
              top: _kPaddingVert,
              left: 8.0,
              right: rightPad,
              child: ClipRect(
                child: AnimatedAlign(
                  duration: const Duration(milliseconds: 150),
                  curve: const Cubic(0.4, 0, 0.2, 1),
                  alignment: AlignmentDirectional.topStart,
                  heightFactor: _isFloating ? 1.0 : 0.0,
                  child: Text.rich(
                    TextSpan(
                      children: [
                        TextSpan(text: labelText),
                        if (widget.required)
                          TextSpan(
                            text: ' *',
                            style: TextStyle(color: c.ext.error),
                          ),
                      ],
                    ),
                    maxLines: 1,
                    overflow: TextOverflow.ellipsis,
                    style: TextStyle(
                      fontFamily: BTTypography.fontFamily,
                      fontSize: 12.0,
                      fontWeight: FontWeight.w500,
                      height: 4 / 3, // 16 px / 12 px
                      color: _labelColor(c, hasError: hasError),
                    ),
                  ),
                ),
              ),
            ),

          // ── Clear button ─────────────────────────────────────────────────
          // Always in the widget tree so AnimatedSlide / AnimatedOpacity can
          // tween between visible and hidden states. IgnorePointer prevents
          // accidental taps while the button is fading out.
          Positioned(
            top: _kPaddingVert,
            right: _kPaddingVert,
            child: IgnorePointer(
              ignoring: !showClear,
              child: AnimatedOpacity(
                opacity: showClear ? 1 : 0,
                duration: const Duration(milliseconds: 180),
                curve: Curves.easeOutCubic,
                child: AnimatedSlide(
                  // Slide in from the right: starts 1× icon-width (16 px)
                  // to the right of its resting position, slides to origin.
                  // Stack(clipBehavior: hardEdge) clips the overshoot cleanly.
                  offset: showClear ? Offset.zero : const Offset(1, 0),
                  duration: const Duration(milliseconds: 180),
                  curve: Curves.easeOutCubic,
                  child: GestureDetector(
                    onTap: _onClear,
                    child:
                        Icon(Icons.cancel, size: 16, color: c.icon.primary),
                  ),
                ),
              ),
            ),
          ),
        ],
      ),
    );

    // ── Scrollbar (conditional) ────────────────────────────────────────────
    // BTScrollbar hardcodes trackVisibility: true, which requires the thumb
    // to also be visible. Only wrap once the scroll controller actually has
    // scrollable content (content > _kMaxHeight). The padding.top positions
    // the track BELOW the floating label, not beside it.
    if (_showScrollbar) {
      field = BTScrollbar(
        controller: _scrollController,
        padding: EdgeInsets.only(
          top: scrollbarTopOffset,
          right: 3.0,
          bottom: _kPaddingVert,
        ),
        child: field,
      );
    }

    // ── Below-field row ────────────────────────────────────────────────────
    // Error text (left, expands) + character counter (right).
    final hasBelow = hasError || widget.maxLength != null;

    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        field,
        if (hasBelow)
          Padding(
            padding: EdgeInsets.only(top: 4.0),
            child: Row(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Expanded(
                  child: hasError
                      ? Text(
                          errorText,
                          style: TextStyle(
                            fontFamily: BTTypography.fontFamily,
                            fontSize: 12.0,
                            fontWeight: FontWeight.w500,
                            height: 4 / 3,
                            color: c.ext.error,
                          ),
                        )
                      : const SizedBox.shrink(),
                ),
                if (widget.maxLength != null)
                  Text(
                    '${_controller.text.length}/${widget.maxLength}',
                    style: TextStyle(
                      fontFamily: BTTypography.fontFamily,
                      fontSize: 12.0,
                      fontWeight: FontWeight.w500,
                      height: 4 / 3,
                      color: hasError ? c.ext.error : c.text.secondary,
                    ),
                  ),
              ],
            ),
          ),
      ],
    );
  }
}

/// BTInputTime — tap-to-open time input field.
///
/// Opens [BTTimePicker] as a centred dialog or a bottom-sheet drawer depending
/// on [showType]. Use the [variant] prop to control which columns are shown
/// in the picker (24-hour, 12-hour, with/without seconds).
///
/// ## Usage
/// ```dart
/// BTInputTime(
///   label: 'Jam Mulai',
///   required: true,
///   value: _time,
///   variant: BTCalendarTimeVariant.hhMm,
///   showType: BTCalendarShowType.drawer,
///   onChanged: (t) => setState(() => _time = t),
///   onClear: () => setState(() => _time = null),
/// )
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/molecules/input/input.types.dart';
import '../../calendar/calendar.types.dart';
import '../../calendar/time_picker.widget.dart';
import 'package:flutter/material.dart';

class BTInputTime extends StatefulWidget {
  const BTInputTime({
    this.label,
    this.required = false,
    this.disabled = false,
    this.readOnly = false,
    this.errorText,
    this.value,
    this.onChanged,
    this.onClear,
    this.showType = BTCalendarShowType.modal,
    this.variant = BTCalendarTimeVariant.hhMm,
    this.size = BTInputSize.normal,
    this.validator,
    super.key,
  });

  /// Label that floats to the top-left when focused or filled.
  final String? label;

  /// Appends " *" (red) to [label] when true.
  final bool required;

  /// Disables all interaction and applies disabled visual state.
  final bool disabled;

  /// Blocks interaction but keeps normal (non-greyed) colours.
  final bool readOnly;

  /// When set, shows the error border and validation text.
  final String? errorText;

  /// Currently selected time.
  final TimeOfDay? value;

  /// Called when a time is confirmed.
  final ValueChanged<TimeOfDay?>? onChanged;

  /// Called when the × button is tapped (value cleared).
  final VoidCallback? onClear;

  /// Whether the picker appears as a modal dialog or a bottom-sheet drawer.
  final BTCalendarShowType showType;

  /// Which columns to show in [BTTimePicker].
  final BTCalendarTimeVariant variant;

  /// Validator for [Form.validate] integration.
  final FormFieldValidator<TimeOfDay?>? validator;

  /// Field height variant — [BTInputSize.normal] (48 px) or [BTInputSize.small] (~40 px).
  final BTInputSize size;

  @override
  State<BTInputTime> createState() => _BTInputTimeState();
}

class _BTInputTimeState extends State<BTInputTime> {
  TimeOfDay? _time;

  /// True while the time picker is open — drives the active (blue) border.
  bool _isOpen = false;

  bool get _hasValue => _time != null;
  bool get _isFloating => _hasValue || _isOpen;

  /// Lowercase format hint matching the selected [BTCalendarTimeVariant].
  String get _formatHint {
    switch (widget.variant) {
      case BTCalendarTimeVariant.hhMm:
        return 'hh:mm';
      case BTCalendarTimeVariant.hhMmSs:
        return 'hh:mm:ss';
      case BTCalendarTimeVariant.amPm:
        return 'hh:mm am/pm';
      case BTCalendarTimeVariant.amPmSs:
        return 'hh:mm:ss am/pm';
    }
  }

  /// Formatted display string for the selected time.
  String get _displayText {
    final t = _time;
    if (t == null) return '';
    final m = t.minute.toString().padLeft(2, '0');
    switch (widget.variant) {
      case BTCalendarTimeVariant.hhMm:
        return '${t.hour.toString().padLeft(2, '0')}:$m';
      case BTCalendarTimeVariant.hhMmSs:
        return '${t.hour.toString().padLeft(2, '0')}:$m:00';
      case BTCalendarTimeVariant.amPm:
        final h12 = t.hourOfPeriod;
        final period = t.period == DayPeriod.am ? 'AM' : 'PM';
        return '${h12.toString().padLeft(2, '0')}:$m $period';
      case BTCalendarTimeVariant.amPmSs:
        final h12 = t.hourOfPeriod;
        final period = t.period == DayPeriod.am ? 'AM' : 'PM';
        return '${h12.toString().padLeft(2, '0')}:$m:00 $period';
    }
  }

  @override
  void initState() {
    super.initState();
    _time = widget.value;
  }

  @override
  void didUpdateWidget(BTInputTime old) {
    super.didUpdateWidget(old);
    if (widget.value != old.value) _time = widget.value;
  }

  Future<void> _onTap() async {
    if (widget.disabled || widget.readOnly) return;
    setState(() => _isOpen = true);

    final result = await BTTimePicker.show(
      context,
      variant: widget.variant,
      initialTime: _time,
      type: widget.showType,
    );

    if (!mounted) return;
    setState(() {
      if (result != null) _time = result;
      _isOpen = false;
    });
    if (result != null) widget.onChanged?.call(result);
  }

  void _onClear() {
    setState(() => _time = null);
    widget.onChanged?.call(null);
    widget.onClear?.call();
  }

  // ── Color helpers ────────────────────────────────────────────────────────────

  Color _borderColor(BTColorTheme c, {required bool hasError}) {
    if (widget.disabled) return c.border.primary;
    if (hasError) return c.ext.error;
    if (_isOpen) return c.brand.primary;
    return c.border.primary;
  }

  Color _labelColor(BTColorTheme c, {required bool hasError}) {
    if (widget.disabled) return c.text.disabled;
    if (hasError) return c.ext.error;
    return c.text.secondary;
  }

  // ── Build ────────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    if (widget.validator != null) {
      return FormField<TimeOfDay?>(
        autovalidateMode: AutovalidateMode.disabled,
        validator: (_) => widget.validator?.call(_time),
        builder: (field) =>
            _buildBody(context, errorText: widget.errorText ?? field.errorText),
      );
    }
    return _buildBody(context, errorText: widget.errorText);
  }

  Widget _buildBody(BuildContext context, {required String? errorText}) {
    final c = context.btColor;
    final hasError = errorText != null;
    final hasLabel = widget.label != null;
    final labelColor = _labelColor(c, hasError: hasError);
    final valueColor = widget.disabled ? c.text.disabled : c.text.primary;
    final iconColor = widget.disabled ? c.text.disabled : c.icon.primary;

    final showClear = _isOpen && _hasValue && !widget.disabled;

    final isSmall = widget.size == BTInputSize.small;

    final double vertPad;
    if (isSmall) {
      vertPad = hasLabel ? (_isFloating ? 4.0 : 12.0) : 12.0;
    } else {
      vertPad = hasLabel ? 8.0 : 16.0;
    }

    final field = AnimatedContainer(
      duration: const Duration(milliseconds: 150),
      curve: const Cubic(0.4, 0, 0.2, 1),
      constraints: isSmall
          ? const BoxConstraints()
          : const BoxConstraints(minHeight: 48),
      decoration: BoxDecoration(
        color: widget.disabled ? c.bg.subtle : c.bg.primary,
        border: Border.all(
          color: _borderColor(c, hasError: hasError),
          width: 1,
        ),
        borderRadius: BorderRadius.circular(BTRadius.sm),
      ),
      child: GestureDetector(
        behavior: HitTestBehavior.translucent,
        onTap: (widget.disabled || widget.readOnly) ? null : _onTap,
        child: Padding(
          padding: EdgeInsets.symmetric(horizontal: 8.0, vertical: vertPad),
          child: Row(
            crossAxisAlignment: CrossAxisAlignment.center,
            children: [
              Icon(Icons.schedule, size: 16, color: iconColor),
              SizedBox(width: 8.0),
              Expanded(
                child: _buildContent(
                  c,
                  labelColor: labelColor,
                  valueColor: valueColor,
                  hasError: hasError,
                  isSmall: isSmall,
                ),
              ),
              ClipRect(
                child: AnimatedAlign(
                  duration: const Duration(milliseconds: 150),
                  curve: const Cubic(0.4, 0, 0.2, 1),
                  alignment: AlignmentDirectional.centerEnd,
                  widthFactor: showClear ? 1.0 : 0.0,
                  child: Row(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      SizedBox(width: 8.0),
                      GestureDetector(
                        onTap: _onClear,
                        child: Icon(
                          Icons.cancel,
                          size: 16,
                          color: c.icon.primary,
                        ),
                      ),
                    ],
                  ),
                ),
              ),
            ],
          ),
        ),
      ),
    );

    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        field,
        if (hasError)
          Padding(
            padding: EdgeInsets.only(top: 4.0),
            child: Text(
              errorText,
              style: TextStyle(
                fontFamily: BTTypography.fontFamily,
                fontSize: 12.0,
                fontWeight: FontWeight.w500,
                height: 4 / 3,
                color: c.ext.error,
              ),
            ),
          ),
      ],
    );
  }

  Widget _buildContent(
    BTColorTheme c, {
    required Color labelColor,
    required Color valueColor,
    required bool hasError,
    required bool isSmall,
  }) {
    final valueFontSize = isSmall ? 12.0 : 14.0;

    // No label: single line, value or format hint.
    if (widget.label == null) {
      final text = _displayText.isEmpty ? _formatHint : _displayText;
      return Text(
        text,
        maxLines: 1,
        overflow: TextOverflow.ellipsis,
        style: TextStyle(
          fontFamily: BTTypography.fontFamily,
          fontSize: valueFontSize,
          fontWeight: FontWeight.w500,
          height: 8 / 7,
          color: _displayText.isEmpty ? c.text.tertiary : valueColor,
        ),
      );
    }

    // With label: floating label + value text (same pattern as BTInput).
    // Not floating → label text acts as the placeholder hint.
    // Floating   → label slides up and value text shows the selected time.
    final displayValue = _isFloating ? _displayText : widget.label!;
    final displayColor = _isFloating ? valueColor : labelColor;

    final labelWidget = ClipRect(
      child: AnimatedAlign(
        duration: const Duration(milliseconds: 150),
        curve: const Cubic(0.4, 0, 0.2, 1),
        alignment: AlignmentDirectional.topStart,
        heightFactor: _isFloating ? 1.0 : 0.0,
        child: Text.rich(
          TextSpan(
            children: [
              TextSpan(text: widget.label),
              if (widget.required)
                TextSpan(
                  text: ' *',
                  style: TextStyle(color: c.ext.error),
                ),
            ],
          ),
          maxLines: 1,
          overflow: TextOverflow.ellipsis,
          style: TextStyle(
            fontFamily: BTTypography.fontFamily,
            fontSize: 12.0,
            fontWeight: FontWeight.w500,
            height: 4 / 3,
            color: labelColor,
          ),
        ),
      ),
    );

    final valueWidget = Text(
      displayValue,
      maxLines: 1,
      overflow: TextOverflow.ellipsis,
      style: TextStyle(
        fontFamily: BTTypography.fontFamily,
        fontSize: valueFontSize,
        fontWeight: FontWeight.w500,
        height: 8 / 7,
        color: displayColor,
      ),
    );

    // Small: natural Column height — outer padding drives the ~40 px field height.
    if (isSmall) {
      return Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [labelWidget, valueWidget],
      );
    }

    // Normal: SizedBox(32) pins content so the field stays exactly 48 px.
    return SizedBox(
      height: 32.0,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          labelWidget,
          Expanded(
            child: Align(
              alignment: AlignmentDirectional.centerStart,
              child: valueWidget,
            ),
          ),
        ],
      ),
    );
  }
}
